const sqlite_agent_actor_where =
    "(?3 IS NOT NULL AND actor_id = ?3)";
const sqlite_agent_session_actor_where =
    "((?2 IS NULL AND session_id IS NULL AND " ++ sqlite_agent_actor_where ++ ") OR (?2 IS NOT NULL AND session_id = ?2 AND " ++ sqlite_agent_actor_where ++ "))";
const sqlite_agent_actor_where_ami =
    "(?3 IS NOT NULL AND ami.actor_id = ?3)";
const sqlite_agent_session_actor_where_ami =
    "((?2 IS NULL AND ami.session_id IS NULL AND " ++ sqlite_agent_actor_where_ami ++ ") OR (?2 IS NOT NULL AND ami.session_id = ?2 AND " ++ sqlite_agent_actor_where_ami ++ "))";
const sqlite_agent_session_where_ami =
    "((?2 IS NULL AND ami.session_id IS NULL) OR (?2 IS NOT NULL AND ami.session_id = ?2))";
const sqlite_session_history_visible_where =
    "role <> '" ++ domain.runtime_command_role ++ "'";

fn idOrMake(allocator: std.mem.Allocator, explicit_id: ?[]const u8, prefix: []const u8) ![]u8 {
    if (explicit_id) |value| return allocator.dupe(u8, value);
    return ids.make(allocator, prefix);
}

fn primitiveRuntimeCategory(allocator: std.mem.Allocator, result_type: []const u8) ![]u8 {
    return std.fmt.allocPrint(allocator, "primitive:{s}", .{result_type});
}

fn primitiveRuntimeKey(allocator: std.mem.Allocator, result_type: []const u8, id: []const u8) ![]u8 {
    return std.fmt.allocPrint(allocator, "primitive:{s}:{s}", .{ result_type, id });
}

fn primitiveRuntimeContent(allocator: std.mem.Allocator, title: []const u8, text: []const u8) ![]u8 {
    if (title.len == 0) return allocator.dupe(u8, text);
    if (text.len == 0 or std.mem.eql(u8, title, text)) return allocator.dupe(u8, title);
    return std.fmt.allocPrint(allocator, "{s}\n{s}", .{ title, text });
}

fn primitiveTypeFromAgentCategory(category: []const u8) ?[]const u8 {
    const prefix = "primitive:";
    if (!std.mem.startsWith(u8, category, prefix)) return null;
    const value = category[prefix.len..];
    if (std.mem.eql(u8, value, "source") or
        std.mem.eql(u8, value, "artifact") or
        std.mem.eql(u8, value, "memory_atom") or
        std.mem.eql(u8, value, "entity") or
        std.mem.eql(u8, value, "relation") or
        std.mem.eql(u8, value, "context_pack"))
    {
        return value;
    }
    return null;
}

fn feedObjectTypeHasVisibleBackingRecord(object_type: []const u8) bool {
    return std.mem.eql(u8, object_type, "source") or
        std.mem.eql(u8, object_type, "artifact") or
        std.mem.eql(u8, object_type, "memory_atom") or
        std.mem.eql(u8, object_type, "entity") or
        std.mem.eql(u8, object_type, "relation") or
        std.mem.eql(u8, object_type, "context_pack") or
        std.mem.eql(u8, object_type, "agent_memory");
}

fn feedReferenceObjectType(value: []const u8) ?[]const u8 {
    if (std.mem.startsWith(u8, value, "src_")) return "source";
    if (std.mem.startsWith(u8, value, "art_")) return "artifact";
    if (std.mem.startsWith(u8, value, "mem_")) return "memory_atom";
    if (std.mem.startsWith(u8, value, "ent_")) return "entity";
    if (std.mem.startsWith(u8, value, "rel_")) return "relation";
    if (std.mem.startsWith(u8, value, "ctx_")) return "context_pack";
    if (std.mem.startsWith(u8, value, "spc_")) return "space";
    return null;
}

fn feedAgentMemoryPayloadIsInternal(allocator: std.mem.Allocator, payload_json: []const u8) !bool {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, payload_json, .{}) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        else => return false,
    };
    defer parsed.deinit();
    if (parsed.value != .object) return false;
    const key = json.stringField(parsed.value.object, "key") orelse "";
    const content = json.stringField(parsed.value.object, "content") orelse "";
    return domain.isInternalMemoryEntryKeyOrContent(key, content);
}

fn isLucidProjectableObjectType(object_type: []const u8) bool {
    return std.mem.eql(u8, object_type, "source") or
        std.mem.eql(u8, object_type, "artifact") or
        std.mem.eql(u8, object_type, "memory_atom") or
        std.mem.eql(u8, object_type, "entity") or
        std.mem.eql(u8, object_type, "relation") or
        std.mem.eql(u8, object_type, "context_pack") or
        std.mem.eql(u8, object_type, "agent_memory");
}

fn primitiveRuntimeObjectId(allocator: std.mem.Allocator, key: []const u8, fallback: []const u8) ![]u8 {
    if (std.mem.startsWith(u8, key, "primitive:")) {
        var parts = std.mem.splitScalar(u8, key, ':');
        _ = parts.next();
        _ = parts.next();
        if (parts.rest().len > 0) return allocator.dupe(u8, parts.rest());
    }
    return allocator.dupe(u8, fallback);
}

fn primitiveRuntimeTitle(allocator: std.mem.Allocator, result_type: []const u8, key: []const u8) ![]u8 {
    const id = try primitiveRuntimeObjectId(allocator, key, key);
    defer allocator.free(id);
    return std.fmt.allocPrint(allocator, "{s}:{s}", .{ result_type, id });
}

fn primitiveRuntimeCitations(allocator: std.mem.Allocator, result_type: ?[]const u8, id: []const u8) ![]const u8 {
    if (result_type) |kind| {
        if (std.mem.eql(u8, kind, "source")) return singleJsonString(allocator, id);
    }
    return allocator.dupe(u8, "[]");
}

fn agentMemoryRuntimeMetadataJson(allocator: std.mem.Allocator, store_name: []const u8, entry: domain.AgentMemory) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"native\":\"agent_memory_runtime\",\"store\":");
    try json.appendString(&out, allocator, store_name);
    try out.appendSlice(allocator, ",\"key\":");
    try json.appendString(&out, allocator, entry.key);
    try out.appendSlice(allocator, ",\"category\":");
    try json.appendString(&out, allocator, entry.category);
    try out.appendSlice(allocator, ",\"session_id\":");
    try json.appendNullableString(&out, allocator, entry.session_id);
    try out.appendSlice(allocator, ",\"scope\":");
    try json.appendString(&out, allocator, entry.scope);
    try out.appendSlice(allocator, ",\"permissions\":");
    try json.appendRawJsonOr(&out, allocator, entry.permissions_json, "[]");
    try out.appendSlice(allocator, ",\"owner_id\":");
    try json.appendString(&out, allocator, entry.actor_id);
    try out.appendSlice(allocator, ",\"writer_actor_id\":");
    try json.appendString(&out, allocator, if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id);
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

fn isAgentMemorySourceMetadata(metadata_json: []const u8) bool {
    return std.mem.indexOf(u8, metadata_json, "\"native\":\"agent_memory\"") != null or
        std.mem.indexOf(u8, metadata_json, "\"native\":\"agent_memory_runtime\"") != null;
}

fn agentMemoryWriteFeedEventType(store_name: []const u8, operation: domain.AgentMemoryOperation) []const u8 {
    const native = std.mem.eql(u8, store_name, "native");
    return switch (operation) {
        .put => if (native) "agent_memory.put" else "agent_memory.runtime_put",
        .merge_object => if (native) "agent_memory.merge_object" else "agent_memory.runtime_merge_object",
        .merge_string_set => if (native) "agent_memory.merge_string_set" else "agent_memory.runtime_merge_string_set",
    };
}

fn agentMemoryDeleteFeedEventType(store_name: []const u8) []const u8 {
    return if (std.mem.eql(u8, store_name, "native")) "agent_memory.delete" else "agent_memory.runtime_delete";
}

fn agentMemoryDeleteAllFeedEventType(store_name: []const u8) []const u8 {
    return if (std.mem.eql(u8, store_name, "native")) "agent_memory.delete_all" else "agent_memory.runtime_delete_all";
}

fn agentMemoryFeedPayloadJson(allocator: std.mem.Allocator, store_name: []const u8, entry: domain.AgentMemory, operation: domain.AgentMemoryOperation, operation_content: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"store\":");
    try json.appendString(&out, allocator, store_name);
    try out.appendSlice(allocator, ",\"key\":");
    try json.appendString(&out, allocator, entry.key);
    try out.appendSlice(allocator, ",\"content\":");
    try json.appendString(&out, allocator, entry.content);
    try out.appendSlice(allocator, ",\"category\":");
    try json.appendString(&out, allocator, entry.category);
    try out.appendSlice(allocator, ",\"session_id\":");
    try json.appendNullableString(&out, allocator, entry.session_id);
    try out.appendSlice(allocator, ",\"scope\":");
    try json.appendString(&out, allocator, entry.scope);
    try out.appendSlice(allocator, ",\"permissions\":");
    try json.appendRawJsonOr(&out, allocator, entry.permissions_json, "[]");
    try out.appendSlice(allocator, ",\"owner_id\":");
    try json.appendString(&out, allocator, entry.actor_id);
    try out.appendSlice(allocator, ",\"writer_actor_id\":");
    try json.appendString(&out, allocator, if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id);
    switch (operation) {
        .put => {},
        .merge_string_set => {
            try out.appendSlice(allocator, ",\"values\":");
            try json.appendRawJsonOr(&out, allocator, operation_content, "[]");
        },
        .merge_object => {
            try out.appendSlice(allocator, ",\"object\":");
            try json.appendRawJsonOr(&out, allocator, operation_content, "{}");
        },
    }
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

