fn agentSessionUsageFeedPayloadJson(allocator: std.mem.Allocator, route: AgentMemoryStorageRoute, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8, scope: []const u8, permissions_json: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"session_id\":");
    try json.appendString(&out, allocator, session_id);
    try out.appendSlice(allocator, ",\"actor_id\":");
    try json.appendNullableString(&out, allocator, actor_id);
    try out.print(allocator, ",\"total_tokens\":{d}", .{total_tokens});
    try out.appendSlice(allocator, ",\"scope\":");
    try json.appendString(&out, allocator, scope);
    try out.appendSlice(allocator, ",\"permissions\":");
    try json.appendRawJsonOr(&out, allocator, permissions_json, "[]");
    try out.append(allocator, '}');
    const payload = try out.toOwnedSlice(allocator);
    defer allocator.free(payload);
    return payloadWithStorageRouteJson(allocator, payload, route);
}

fn agentSessionUsageDeleteFeedPayloadJson(allocator: std.mem.Allocator, route: AgentMemoryStorageRoute, session_id: []const u8, actor_id: ?[]const u8, scope: []const u8, permissions_json: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"session_id\":");
    try json.appendString(&out, allocator, session_id);
    try out.appendSlice(allocator, ",\"actor_id\":");
    try json.appendNullableString(&out, allocator, actor_id);
    try out.appendSlice(allocator, ",\"scope\":");
    try json.appendString(&out, allocator, scope);
    try out.appendSlice(allocator, ",\"permissions\":");
    try json.appendRawJsonOr(&out, allocator, permissions_json, "[]");
    try out.append(allocator, '}');
    const payload = try out.toOwnedSlice(allocator);
    defer allocator.free(payload);
    return payloadWithStorageRouteJson(allocator, payload, route);
}

fn firstScopeOrDefault(allocator: std.mem.Allocator, scopes_json: []const u8, fallback: []const u8) ![]const u8 {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, scopes_json, .{}) catch return allocator.dupe(u8, fallback);
    defer parsed.deinit();
    if (parsed.value == .array) {
        for (parsed.value.array.items) |item| {
            if (item == .string and item.string.len > 0) return allocator.dupe(u8, item.string);
        }
    }
    return allocator.dupe(u8, fallback);
}

fn hygieneCanVerify(input: HygieneRunInput, scope: []const u8, permissions_json: []const u8) bool {
    return domain.hasCapability(input.scopes_json, input.capabilities_json, "verify") and
        domain.scopeVerifiable(scope, input.scopes_json) and
        domain.permissionsWritable(permissions_json, input.scopes_json);
}

fn hygieneCanDelete(input: HygieneRunInput, scope: []const u8, permissions_json: []const u8) bool {
    return domain.hasCapability(input.scopes_json, input.capabilities_json, "delete") and
        domain.scopeDeletable(scope, input.scopes_json) and
        domain.permissionsWritable(permissions_json, input.scopes_json);
}

pub const BackendKind = enum {
    sqlite,
    postgres,

    pub fn parse(value: []const u8) BackendKind {
        if (std.mem.eql(u8, value, "postgres")) return .postgres;
        return .sqlite;
    }
};

pub const AgentMemoryStorageTarget = enum {
    primary,
    native,
    runtime,
    named,
    subset,
    all,
};

pub const AgentMemoryStorageRoute = struct {
    target: AgentMemoryStorageTarget = .primary,
    name: ?[]const u8 = null,
    stores: []const []const u8 = &.{},

    pub fn parse(raw: ?[]const u8) AgentMemoryStorageRoute {
        const value = raw orelse return .{};
        if (std.ascii.eqlIgnoreCase(value, "primary")) return .{ .target = .primary };
        if (std.ascii.eqlIgnoreCase(value, "default")) return .{ .target = .primary };
        if (std.ascii.eqlIgnoreCase(value, "native")) return .{ .target = .native };
        if (std.ascii.eqlIgnoreCase(value, "canonical")) return .{ .target = .native };
        if (std.ascii.eqlIgnoreCase(value, "sqlite")) return .{ .target = .native };
        if (std.ascii.eqlIgnoreCase(value, "postgres")) return .{ .target = .native };
        if (std.ascii.eqlIgnoreCase(value, "runtime")) return .{ .target = .runtime };
        if (std.ascii.eqlIgnoreCase(value, "external")) return .{ .target = .runtime };
        if (std.ascii.eqlIgnoreCase(value, "redis")) return .{ .target = .runtime };
        if (std.ascii.eqlIgnoreCase(value, "all")) return .{ .target = .all };
        if (std.ascii.eqlIgnoreCase(value, "federated")) return .{ .target = .all };
        return .{ .target = .named, .name = value };
    }

    pub fn fromStores(stores: []const []const u8) AgentMemoryStorageRoute {
        if (stores.len == 0) return .{};
        if (stores.len == 1) return parse(stores[0]);
        return .{ .target = .subset, .stores = stores };
    }
};

const PrimitiveMirrorKind = enum {
    source,
    artifact,
    memory_atom,
    entity,
    relation,
    context_pack,

    fn resultType(self: PrimitiveMirrorKind) []const u8 {
        return switch (self) {
            .source => "source",
            .artifact => "artifact",
            .memory_atom => "memory_atom",
            .entity => "entity",
            .relation => "relation",
            .context_pack => "context_pack",
        };
    }
};

fn primitiveLifecycleUsesOverlay(object_type: []const u8) bool {
    return std.mem.eql(u8, object_type, "source") or
        std.mem.eql(u8, object_type, "entity") or
        std.mem.eql(u8, object_type, "context_pack") or
        std.mem.eql(u8, object_type, "space") or
        std.mem.eql(u8, object_type, "policy_scope");
}

fn lucidProjectionKey(allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8) ![]u8 {
    return std.fmt.allocPrint(allocator, "{s}:{s}", .{ object_type, object_id });
}

fn agentMemoryProjectionKey(allocator: std.mem.Allocator, entry: domain.AgentMemory) ![]u8 {
    return agentMemoryProjectionKeyFromParts(allocator, entry.key, entry.session_id, entry.actor_id);
}

fn agentMemoryProjectionKeyFromParts(allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8) ![]u8 {
    return std.fmt.allocPrint(allocator, "agent_memory:{s}:{s}:{s}", .{ actor_id orelse "unknown", session_id orelse "global", key });
}

fn lucidTypeForPrimitive(object_type: []const u8, title: []const u8, text: []const u8) []const u8 {
    if (std.mem.eql(u8, object_type, "memory_atom")) return lucid_runtime.typeForMemoryAtom(title, text);
    if (std.mem.eql(u8, object_type, "agent_memory")) return lucid_runtime.typeForAgentCategory(title);
    if (std.mem.eql(u8, object_type, "artifact")) {
        if (std.ascii.eqlIgnoreCase(title, "decision") or std.ascii.eqlIgnoreCase(title, "adr")) return "decision";
        if (std.ascii.eqlIgnoreCase(title, "meeting_note")) return "conversation";
        if (std.ascii.eqlIgnoreCase(title, "runbook") or std.ascii.eqlIgnoreCase(title, "recipe")) return "context";
    }
    if (std.mem.eql(u8, object_type, "context_pack")) return "context";
    return "learning";
}

fn lucidProjectionJobInputJson(allocator: std.mem.Allocator, action: []const u8, key: []const u8, content: []const u8, lucid_type: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"action\":");
    try json.appendString(&out, allocator, action);
    try out.appendSlice(allocator, ",\"key\":");
    try json.appendString(&out, allocator, key);
    try out.appendSlice(allocator, ",\"content\":");
    try json.appendString(&out, allocator, content);
    try out.appendSlice(allocator, ",\"type\":");
    try json.appendString(&out, allocator, lucid_type);
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

fn lifecycleScopeFromRequiredScopesJson(allocator: std.mem.Allocator, required_scopes_json: []const u8) ![]const u8 {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, required_scopes_json, .{}) catch return allocator.dupe(u8, "public");
    defer parsed.deinit();
    if (parsed.value != .array) return allocator.dupe(u8, "public");
    for (parsed.value.array.items) |item| {
        if (item != .string) continue;
        if (std.mem.eql(u8, item.string, "public")) continue;
        return allocator.dupe(u8, item.string);
    }
    return allocator.dupe(u8, "public");
}

pub const StoreOptions = struct {
    agent_memory: agent_memory_runtime.Config = .{},
    agent_memory_stores: []const agent_memory_runtime.NamedConfig = &.{},
    vector_backend: vector_runtime.Config = .{},
    analytics_backend: analytics_runtime.Config = .{},
    lucid_projection: lucid_runtime.Config = .{},
};

pub const Store = struct {
    allocator: std.mem.Allocator,
    backend: Backend,
    agent_memory: agent_memory_runtime.Runtime = .native,
    agent_memory_stores: agent_memory_runtime.RuntimeRegistry,
    vector_backend: vector_runtime.Config = .{},
    vector_runtime: vector_runtime.Runtime = .{},
    analytics_backend: analytics_runtime.Config = .{},
    lucid_projection: lucid_runtime.Runtime = .{},

    pub const Backend = union(BackendKind) {
        sqlite: SQLiteStore,
        postgres: PostgresStore,
    };

    pub fn initSQLite(allocator: std.mem.Allocator, db_path: [:0]const u8) !Store {
        return initSQLiteWithOptions(allocator, db_path, .{});
    }

    pub fn initSQLiteWithOptions(allocator: std.mem.Allocator, db_path: [:0]const u8, options: StoreOptions) !Store {
        var backend = try SQLiteStore.init(allocator, db_path);
        errdefer backend.deinit();
        var agent_memory = try agent_memory_runtime.Runtime.init(allocator, options.agent_memory);
        errdefer agent_memory.deinit();
        var agent_memory_stores = try agent_memory_runtime.RuntimeRegistry.init(allocator, options.agent_memory_stores);
        errdefer agent_memory_stores.deinit();
        return .{
            .allocator = allocator,
            .backend = .{ .sqlite = backend },
            .agent_memory = agent_memory,
            .agent_memory_stores = agent_memory_stores,
            .vector_backend = options.vector_backend,
            .vector_runtime = vector_runtime.Runtime.init(options.vector_backend),
            .analytics_backend = options.analytics_backend,
            .lucid_projection = lucid_runtime.Runtime.init(options.lucid_projection),
        };
    }

    pub fn initPostgres(allocator: std.mem.Allocator, url: []const u8) !Store {
        return initPostgresWithOptions(allocator, url, .{});
    }

    pub fn initPostgresWithOptions(allocator: std.mem.Allocator, url: []const u8, options: StoreOptions) !Store {
        var backend = try PostgresStore.init(allocator, url);
        errdefer backend.deinit();
        var agent_memory = try agent_memory_runtime.Runtime.init(allocator, options.agent_memory);
        errdefer agent_memory.deinit();
        var agent_memory_stores = try agent_memory_runtime.RuntimeRegistry.init(allocator, options.agent_memory_stores);
        errdefer agent_memory_stores.deinit();
        return .{
            .allocator = allocator,
            .backend = .{ .postgres = backend },
            .agent_memory = agent_memory,
            .agent_memory_stores = agent_memory_stores,
            .vector_backend = options.vector_backend,
            .vector_runtime = vector_runtime.Runtime.init(options.vector_backend),
            .analytics_backend = options.analytics_backend,
            .lucid_projection = lucid_runtime.Runtime.init(options.lucid_projection),
        };
    }

    pub fn deinit(self: *Store) void {
        self.agent_memory.deinit();
        self.agent_memory_stores.deinit();
        switch (self.backend) {
            .sqlite => |*s| s.deinit(),
            .postgres => |*p| p.deinit(),
        }
    }

    pub fn health(self: *Store) bool {
        return switch (self.backend) {
            .sqlite => |*s| s.health(),
            .postgres => |*p| p.health(),
        };
    }

    pub fn backendName(self: *Store) []const u8 {
        return switch (self.backend) {
            .sqlite => "sqlite",
            .postgres => "postgres",
        };
    }

    pub fn agentMemoryBackendName(self: *Store) []const u8 {
        return self.agent_memory.backendName();
    }

    pub fn vectorBackendName(self: *Store) []const u8 {
        return self.vector_backend.backend.name();
    }

    pub fn vectorExternalSinksJson(self: *Store) []const u8 {
        return switch (self.vector_backend.backend) {
            .local => "[]",
            .qdrant => "[\"qdrant\"]",
            .lancedb => "[\"lancedb\"]",
            .lancedb_http => "[\"lancedb_http\"]",
        };
    }

    pub fn analyticsBackendName(self: *Store) []const u8 {
        return self.analytics_backend.backend.name();
    }

    pub fn lucidBackendName(self: *Store) []const u8 {
        return self.lucid_projection.backendName();
    }

    fn enqueueLucidProjectionPut(
        self: *Store,
        allocator: std.mem.Allocator,
        object_type: []const u8,
        object_id: []const u8,
        title: []const u8,
        text: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
    ) !void {
        if (!self.lucid_projection.canProject(scope, permissions_json)) return;
        const key = if (std.mem.eql(u8, object_type, "agent_memory"))
            try allocator.dupe(u8, object_id)
        else
            try lucidProjectionKey(allocator, object_type, object_id);
        defer allocator.free(key);
        const lucid_type = lucidTypeForPrimitive(object_type, title, text);
        const input_json = try lucidProjectionJobInputJson(allocator, "put", key, text, lucid_type);
        defer allocator.free(input_json);
        _ = try self.createJob(allocator, .{
            .job_type = "lucid_projection",
            .scope = scope,
            .permissions_json = permissions_json,
            .object_type = object_type,
            .object_id = object_id,
            .input_json = input_json,
            .actor_id = actor_id,
        });
    }

    fn enqueueLucidProjectionDelete(
        self: *Store,
        allocator: std.mem.Allocator,
        object_type: []const u8,
        object_id: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
    ) !void {
        if (!self.lucid_projection.canProject(scope, permissions_json)) return;
        const key = if (std.mem.eql(u8, object_type, "agent_memory"))
            try allocator.dupe(u8, object_id)
        else
            try lucidProjectionKey(allocator, object_type, object_id);
        defer allocator.free(key);
        const input_json = try lucidProjectionJobInputJson(allocator, "delete", key, "", "learning");
        defer allocator.free(input_json);
        _ = try self.createJob(allocator, .{
            .job_type = "lucid_projection",
            .scope = scope,
            .permissions_json = permissions_json,
            .object_type = object_type,
            .object_id = object_id,
            .input_json = input_json,
            .actor_id = actor_id,
        });
    }

    fn enqueueAgentMemoryLucidPut(self: *Store, allocator: std.mem.Allocator, entry: domain.AgentMemory, actor_id: ?[]const u8) !void {
        const projection_key = try agentMemoryProjectionKey(allocator, entry);
        defer allocator.free(projection_key);
        try self.enqueueLucidProjectionPut(allocator, "agent_memory", projection_key, entry.category, entry.content, entry.scope, entry.permissions_json, actor_id);
    }

    fn enqueueAgentMemoryLucidDelete(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, scope: []const u8, permissions_json: []const u8, writer_actor_id: ?[]const u8) !void {
        const projection_key = try agentMemoryProjectionKeyFromParts(allocator, key, session_id, actor_id);
        defer allocator.free(projection_key);
        try self.enqueueLucidProjectionDelete(allocator, "agent_memory", projection_key, scope, permissions_json, writer_actor_id);
    }

    fn syncMemoryAtomLucidProjection(self: *Store, allocator: std.mem.Allocator, id: []const u8, status: []const u8, actor_id: ?[]const u8) !void {
        if (!self.lucid_projection.isEnabled()) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        if (domain.isDefaultVisibleStatus(status)) {
            if (try self.getMemoryAtom(temp, id)) |atom| {
                try self.enqueueLucidProjectionPut(temp, "memory_atom", atom.id, atom.predicate, atom.text, atom.scope, atom.permissions_json, actor_id);
            }
            return;
        }
        if (try self.getMemoryAtom(temp, id)) |atom| {
            try self.enqueueLucidProjectionDelete(temp, "memory_atom", atom.id, atom.scope, atom.permissions_json, actor_id);
        }
    }

    fn syncArtifactLucidProjection(self: *Store, allocator: std.mem.Allocator, id: []const u8, status: []const u8, actor_id: ?[]const u8) !void {
        if (!self.lucid_projection.isEnabled()) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        if (domain.isDefaultVisibleStatus(status)) {
            if (try self.getArtifact(temp, id)) |artifact| {
                try self.enqueueLucidProjectionPut(temp, "artifact", artifact.id, artifact.artifact_type, artifact.body, artifact.scope, artifact.permissions_json, actor_id);
            }
            return;
        }
        if (try self.getArtifact(temp, id)) |artifact| {
            try self.enqueueLucidProjectionDelete(temp, "artifact", artifact.id, artifact.scope, artifact.permissions_json, actor_id);
        }
    }

    fn syncRelationLucidProjection(self: *Store, allocator: std.mem.Allocator, id: []const u8, status: []const u8, actor_id: ?[]const u8) !void {
        if (!self.lucid_projection.isEnabled()) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        if (try self.getRelation(temp, id)) |relation| {
            if (domain.isDefaultVisibleStatus(status)) {
                const relation_text = try std.fmt.allocPrint(temp, "{s} {s} {s}", .{ relation.from_entity_id, relation.relation_type, relation.to_entity_id });
                try self.enqueueLucidProjectionPut(temp, "relation", relation.id, relation.relation_type, relation_text, relation.scope, relation.permissions_json, actor_id);
            } else {
                try self.enqueueLucidProjectionDelete(temp, "relation", relation.id, relation.scope, relation.permissions_json, actor_id);
            }
        }
    }

    fn syncOverlayPrimitiveLucidProjection(self: *Store, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, status: []const u8, actor_id: ?[]const u8) !void {
        if (!self.lucid_projection.isEnabled()) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        if (std.mem.eql(u8, object_type, "source")) {
            if (try self.getSource(temp, object_id)) |source| {
                if (domain.isDefaultVisibleStatus(status)) {
                    try self.enqueueLucidProjectionPut(temp, "source", source.id, source.title, source.content, source.scope, source.permissions_json, actor_id);
                } else {
                    try self.enqueueLucidProjectionDelete(temp, "source", source.id, source.scope, source.permissions_json, actor_id);
                }
            }
            return;
        }
        if (std.mem.eql(u8, object_type, "entity")) {
            if (try self.getEntity(temp, object_id)) |entity| {
                const text = entity.description orelse entity.name;
                if (domain.isDefaultVisibleStatus(status)) {
                    try self.enqueueLucidProjectionPut(temp, "entity", entity.id, entity.name, text, entity.scope, entity.permissions_json, actor_id);
                } else {
                    try self.enqueueLucidProjectionDelete(temp, "entity", entity.id, entity.scope, entity.permissions_json, actor_id);
                }
            }
            return;
        }
        if (std.mem.eql(u8, object_type, "context_pack") and !domain.isDefaultVisibleStatus(status)) {
            try self.enqueueLucidProjectionDelete(temp, "context_pack", object_id, "public", "[]", actor_id);
        }
    }

    fn mirrorKnowledgePrimitiveToRuntime(
        self: *Store,
        allocator: std.mem.Allocator,
        runtime: *agent_memory_runtime.Runtime,
        kind: PrimitiveMirrorKind,
        id: []const u8,
        title: []const u8,
        text: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
    ) !void {
        _ = self;
        const key = try primitiveRuntimeKey(allocator, kind.resultType(), id);
        const content = try primitiveRuntimeContent(allocator, title, text);
        const category = try primitiveRuntimeCategory(allocator, kind.resultType());
        _ = try runtime.store(allocator, .{
            .key = key,
            .content = content,
            .category = category,
            .scope = scope,
            .permissions_json = permissions_json,
            .actor_id = actor_id,
            .writer_actor_id = actor_id,
        });
    }

    fn mirrorKnowledgePrimitive(
        self: *Store,
        allocator: std.mem.Allocator,
        kind: PrimitiveMirrorKind,
        id: []const u8,
        title: []const u8,
        text: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
        route: AgentMemoryStorageRoute,
    ) !void {
        switch (route.target) {
            .primary => {
                if (self.agent_memory.isExternal()) {
                    self.mirrorKnowledgePrimitiveToRuntime(allocator, &self.agent_memory, kind, id, title, text, scope, permissions_json, actor_id) catch {};
                }
            },
            .native => {},
            .runtime => {
                if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
                try self.mirrorKnowledgePrimitiveToRuntime(allocator, &self.agent_memory, kind, id, title, text, scope, permissions_json, actor_id);
            },
            .named => {
                const runtime = try self.namedAgentMemoryRuntime(route);
                try self.mirrorKnowledgePrimitiveToRuntime(allocator, runtime, kind, id, title, text, scope, permissions_json, actor_id);
            },
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| {
                    try self.mirrorKnowledgePrimitive(allocator, kind, id, title, text, scope, permissions_json, actor_id, routeForSubsetStoreName(store_name));
                }
            },
            .all => {
                if (self.agent_memory.isExternal()) {
                    try self.mirrorKnowledgePrimitiveToRuntime(allocator, &self.agent_memory, kind, id, title, text, scope, permissions_json, actor_id);
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    try self.mirrorKnowledgePrimitiveToRuntime(allocator, &named.runtime, kind, id, title, text, scope, permissions_json, actor_id);
                }
            },
        }
    }

    fn ensureKnowledgePrimitiveMirrorRoute(self: *Store, route: AgentMemoryStorageRoute) !void {
        switch (route.target) {
            .primary, .native => {},
            .runtime => if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable,
            .named => _ = try self.namedAgentMemoryRuntime(route),
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| try self.ensureKnowledgePrimitiveMirrorRoute(routeForSubsetStoreName(store_name));
            },
            .all => {},
        }
    }

    fn recordVisibleWithPolicyForActor(self: *Store, allocator: std.mem.Allocator, scope: []const u8, permissions_json: []const u8, scopes_json: []const u8, actor_id: ?[]const u8) !bool {
        return switch (self.backend) {
            .sqlite => |*s| s.recordVisibleWithPolicyForActor(allocator, scope, permissions_json, scopes_json, actor_id),
            .postgres => |*p| p.recordVisibleWithPolicyForActor(allocator, scope, permissions_json, scopes_json, actor_id),
        };
    }

    pub fn schemaVersion(self: *Store) !i64 {
        return switch (self.backend) {
            .sqlite => |*s| s.schemaVersion(),
