    pub fn rebuildVectorIndex(self: *Store, allocator: std.mem.Allocator, input: VectorMaintenanceInput) !VectorMaintenanceResult {
        const requeued = if (input.retry_failed) try self.requeueVectorOutboxFailures() else 0;
        if (input.reset_external and self.vector_backend.externalEnabled()) {
            try vector_runtime.resetWithRuntime(allocator, self.vector_backend, &self.vector_runtime);
        }
        var result = try self.enqueueVectorUpsertsFromCanonical(allocator, input.limit);
        result.requeued_failed = requeued;
        return result;
    }

    pub fn reconcileVectorIndex(self: *Store, allocator: std.mem.Allocator, input: VectorMaintenanceInput) !VectorMaintenanceResult {
        const requeued = if (input.retry_failed) try self.requeueVectorOutboxFailures() else 0;
        var result = try self.enqueueVectorUpsertsFromCanonical(allocator, input.limit);
        result.requeued_failed = requeued;
        return result;
    }

    fn enqueueVectorUpsertsFromCanonical(self: *Store, allocator: std.mem.Allocator, limit: usize) !VectorMaintenanceResult {
        const capped = @max(@as(usize, 1), @min(limit, 10000));
        const chunks = try self.listVectorChunks(allocator, capped, 0);
        defer {
            for (chunks) |*chunk| deinitVectorChunk(allocator, chunk);
            allocator.free(chunks);
        }
        var enqueued: usize = 0;
        for (chunks) |chunk| {
            const payload = try vectorUpsertPayloadJson(allocator, chunk.id);
            defer allocator.free(payload);
            _ = try self.enqueueVectorOutbox(.{
                .action = "upsert",
                .object_type = chunk.object_type,
                .object_id = chunk.object_id,
                .payload_json = payload,
            });
            enqueued += 1;
        }
        return .{
            .canonical_chunks = chunks.len,
            .enqueued_upserts = enqueued,
            .external_enabled = self.vector_backend.externalEnabled(),
        };
    }

    pub fn runVectorOutbox(self: *Store, limit: usize) !VectorOutboxRunResult {
        return self.runVectorOutboxAs(limit, default_vector_outbox_worker_id);
    }

    pub fn runVectorOutboxAs(self: *Store, limit: usize, worker_id: []const u8) !VectorOutboxRunResult {
        if (self.vector_backend.externalEnabled()) return self.runExternalVectorOutbox(limit, worker_id);
        return switch (self.backend) {
            .sqlite => |*s| s.runVectorOutbox(limit),
            .postgres => |*p| p.runVectorOutbox(limit),
        };
    }

    fn runExternalVectorOutbox(self: *Store, limit: usize, worker_id: []const u8) !VectorOutboxRunResult {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const entries = try self.listVectorOutbox(allocator, .{ .status = "pending", .limit = limit });
        var result = VectorOutboxRunResult{};
        for (entries) |entry| {
            if (std.mem.eql(u8, entry.action, "embed")) continue;
            if (!try self.claimVectorOutboxAs(entry.id, worker_id)) continue;
            const vector_id = vectorIdFromOutboxPayload(allocator, entry.payload_json) catch {
                _ = try self.finishVectorOutboxAs(entry.id, "failed_external_index", worker_id);
                result.failed += 1;
                continue;
            };
            if (std.mem.eql(u8, entry.action, "delete")) {
                vector_runtime.deleteWithRuntime(allocator, self.vector_backend, &self.vector_runtime, vector_id) catch |err| {
                    if (err == error.VectorBackendCircuitOpen) {
                        _ = try self.finishVectorOutboxAs(entry.id, "pending", worker_id);
                        break;
                    } else {
                        _ = try self.finishVectorOutboxAs(entry.id, "failed_external_delete", worker_id);
                        result.failed += 1;
                        continue;
                    }
                };
                _ = try self.finishVectorOutboxAs(entry.id, "deleted_external", worker_id);
                result.processed += 1;
                continue;
            }
            const chunk = (try self.getVectorChunk(allocator, vector_id)) orelse {
                _ = try self.finishVectorOutboxAs(entry.id, "failed_external_index", worker_id);
                result.failed += 1;
                continue;
            };
            vector_runtime.upsertWithRuntime(allocator, self.vector_backend, &self.vector_runtime, vectorChunkUpsertInput(chunk)) catch |err| {
                if (err == error.VectorBackendCircuitOpen) {
                    _ = try self.finishVectorOutboxAs(entry.id, "pending", worker_id);
                    break;
                } else {
                    _ = try self.finishVectorOutboxAs(entry.id, "failed_external_index", worker_id);
                    result.failed += 1;
                    continue;
                }
            };
            _ = try self.finishVectorOutboxAs(entry.id, "indexed_external", worker_id);
            result.processed += 1;
        }
        return result;
    }

