    pub fn createContextPack(self: *Store, allocator: std.mem.Allocator, input: ContextPackInput) !ContextPackResult {
        try self.ensureKnowledgePrimitiveMirrorRoute(input.agent_memory_route);
        var owns_search_results = false;
        const search_results = if (input.preselected_results) |results|
            results
        else blk: {
            owns_search_results = true;
            break :blk try self.search(allocator, .{
                .query = input.query,
                .limit = input.retrieval_limit,
                .scopes_json = input.scopes_json,
                .include_deprecated = input.include_deprecated,
                .include_sessions = input.include_sessions,
                .session_id = input.session_id,
                .use_vector = input.use_vector,
                .adaptive_retrieval = input.adaptive_retrieval,
                .use_temporal_decay = input.use_temporal_decay,
                .use_mmr = input.use_mmr,
                .allow_reranker = input.allow_reranker,
                .min_relevance = input.min_relevance,
                .query_embedding_json = input.query_embedding_json,
                .query_embedding_provider = input.query_embedding_provider,
                .embedding_dimensions = input.embedding_dimensions,
                .actor_id = input.actor_id,
                .agent_memory_route = input.agent_memory_route,
            });
        };
        defer if (owns_search_results) allocator.free(search_results);
        var routed_input = input;
        routed_input.preselected_results = search_results;
        const pack = try switch (self.backend) {
            .sqlite => |*s| s.createContextPack(allocator, routed_input),
            .postgres => |*p| p.createContextPack(allocator, routed_input),
        };
        const scope = try contextPackFeedScope(allocator, pack);
        defer allocator.free(scope);
        const permissions = try contextPackFeedPermissions(allocator, pack);
        defer allocator.free(permissions);
        if (pack.persisted) {
            if (!input.suppress_feed) try self.appendContextPackPutFeedEvent(allocator, pack, scope, permissions, input.actor_id, input.agent_memory_route);
            try self.mirrorKnowledgePrimitive(allocator, .context_pack, pack.id, pack.query, pack.generated_summary, scope, permissions, input.actor_id, input.agent_memory_route);
            try self.enqueueLucidProjectionPut(allocator, "context_pack", pack.id, pack.query, pack.generated_summary, scope, permissions, input.actor_id);
        }
        return pack;
    }

    pub fn importContextPackSnapshot(self: *Store, allocator: std.mem.Allocator, input: ContextPackSnapshotInput) !ContextPackResult {
        try self.ensureKnowledgePrimitiveMirrorRoute(.{});
        const pack = try switch (self.backend) {
            .sqlite => |*s| s.importContextPackSnapshot(allocator, input),
            .postgres => |*p| p.importContextPackSnapshot(allocator, input),
        };
        if (!input.suppress_feed) {
            const scope = try contextPackFeedScope(allocator, pack);
            defer allocator.free(scope);
            const permissions = try contextPackFeedPermissions(allocator, pack);
            defer allocator.free(permissions);
            try self.appendContextPackPutFeedEvent(allocator, pack, scope, permissions, input.actor_id, .{});
            try self.mirrorKnowledgePrimitive(allocator, .context_pack, pack.id, pack.query, pack.generated_summary, scope, permissions, input.actor_id, .{});
            try self.enqueueLucidProjectionPut(allocator, "context_pack", pack.id, pack.query, pack.generated_summary, scope, permissions, input.actor_id);
        }
        return pack;
    }

    pub fn importMemoryAtomsAtomic(self: *Store, allocator: std.mem.Allocator, inputs: []const PreparedMemoryImport) ![]domain.MemoryAtom {
        return switch (self.backend) {
            .sqlite => |*s| s.importMemoryAtomsAtomic(allocator, inputs),
            .postgres => |*p| p.importMemoryAtomsAtomic(allocator, inputs),
        };
    }

    pub fn applyFeedMemoryAtomAtomic(self: *Store, allocator: std.mem.Allocator, input: FeedMemoryApplyInput) !FeedMemoryApplyResult {
        try self.ensureKnowledgePrimitiveMirrorRoute(input.prepared.atom.storage_route);
        var routed_input = input;
        var routed_event = input.event;
        const event_payload_json = try payloadWithStorageRouteJson(allocator, input.event.payload_json, input.prepared.atom.storage_route);
        defer allocator.free(event_payload_json);
        routed_event.payload_json = event_payload_json;
        routed_input.event = routed_event;
        const result = try switch (self.backend) {
            .sqlite => |*s| s.applyFeedMemoryAtomAtomic(allocator, routed_input),
            .postgres => |*p| p.applyFeedMemoryAtomAtomic(allocator, routed_input),
        };
        if (input.prepared.atom.storage_route.target != .primary and !std.mem.eql(u8, result.atom.predicate, "agent.memory")) {
            try self.mirrorKnowledgePrimitive(allocator, .memory_atom, result.atom.id, result.atom.predicate, result.atom.text, result.atom.scope, result.atom.permissions_json, input.prepared.atom.actor_id, input.prepared.atom.storage_route);
        }
        return result;
    }

    pub fn applyFeedAgentMemoryAtomic(self: *Store, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput) !FeedAgentMemoryApplyResult {
        return switch (self.backend) {
            .sqlite => |*s| s.applyFeedAgentMemoryAtomic(allocator, input),
            .postgres => |*p| p.applyFeedAgentMemoryAtomic(allocator, input),
        };
    }

    pub fn effectiveAgentMemoryEventRoute(self: *Store, route: AgentMemoryStorageRoute) AgentMemoryStorageRoute {
        if (route.target == .primary and self.agent_memory.isExternal()) return .{ .target = .runtime };
        return route;
    }

    pub fn applyFeedAgentMemoryRouted(self: *Store, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput, route: AgentMemoryStorageRoute) !FeedAgentMemoryApplyResult {
        const effective_route = self.effectiveAgentMemoryEventRoute(route);
        return switch (effective_route.target) {
            .primary, .native => self.applyFeedAgentMemoryAtomic(allocator, input),
            .runtime, .named, .subset, .all => self.applyFeedAgentMemoryRuntime(allocator, input, effective_route),
        };
    }

    fn applyFeedAgentMemoryRuntime(self: *Store, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput, route: AgentMemoryStorageRoute) !FeedAgentMemoryApplyResult {
        const effective_route = self.effectiveAgentMemoryEventRoute(route);
        return switch (effective_route.target) {
            .primary, .native => self.applyFeedAgentMemoryAtomic(allocator, input),
            .runtime, .named, .subset, .all => self.applyFeedAgentMemoryRuntimeInner(allocator, input, effective_route),
        };
    }

    fn applyFeedAgentMemoryRuntimeInner(self: *Store, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput, route: AgentMemoryStorageRoute) !FeedAgentMemoryApplyResult {
        var object_id: []const u8 = input.delete_key orelse "agent_memory";
        var entry: ?domain.AgentMemory = null;
        var deleted = false;
        const event_payload_json = try payloadWithStorageRouteJson(allocator, input.event.payload_json, route);
        defer allocator.free(event_payload_json);
        if (input.input) |memory_input| {
            var auditable = memory_input;
            if (auditable.writer_actor_id == null) auditable.writer_actor_id = input.writer_actor_id orelse input.event.actor_id;
            auditable.suppress_feed = true;
            const saved = try self.agentMemoryStoreRouted(allocator, auditable, route);
            object_id = saved.id;
            entry = saved;
        } else if (input.delete_key) |key| {
            deleted = if (input.delete_all)
                try self.agentMemoryDeleteAllRoutedInner(key, input.delete_owner_actor_id, input.writer_actor_id orelse input.event.actor_id, route, true)
            else
                try self.agentMemoryDeleteRoutedInner(key, input.delete_session_id, input.delete_owner_actor_id, input.writer_actor_id orelse input.event.actor_id, route, true);
            object_id = key;
        }

        const event_id = if (input.reserved_event_id) |reserved| blk: {
            if (!try self.markFeedEventApplied(reserved, input.event.object_type, object_id, event_payload_json)) return error.FeedReservationConsumed;
            break :blk reserved;
        } else try self.appendFeedEvent(.{
            .event_type = input.event.event_type,
            .operation = input.event.operation,
            .object_type = input.event.object_type,
            .object_id = object_id,
            .scope = input.event.scope,
            .permissions_json = input.event.permissions_json,
            .actor_id = input.event.actor_id,
            .dedupe_key = input.event.dedupe_key,
            .causality_json = input.event.causality_json,
            .payload_json = event_payload_json,
            .status = "applied",
        });
        return .{ .event_id = event_id, .object_id = object_id, .entry = entry, .deleted = deleted };
    }

    pub fn applyExtractedKnowledge(self: *Store, allocator: std.mem.Allocator, input: ExtractedKnowledgeInput) !ExtractedKnowledgeResult {
        const result = try switch (self.backend) {
            .sqlite => |*s| s.applyExtractedKnowledge(allocator, input),
            .postgres => |*p| p.applyExtractedKnowledge(allocator, input),
        };
        if (result.artifact) |artifact| try self.appendArtifactPutFeedEvent(allocator, artifact, input.actor_id, .{});
        for (result.entities) |entity| try self.appendEntityPutFeedEvent(allocator, entity, input.actor_id, .{});
        for (result.relations) |relation| try self.appendRelationPutFeedEvent(allocator, relation, input.actor_id, .{});
        for (result.atoms) |atom| {
            if (!std.mem.eql(u8, atom.predicate, "agent.memory")) try self.appendMemoryAtomPutFeedEvent(allocator, atom, input.actor_id, .{});
        }
        return result;
    }

    pub fn agentMemoryStore(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput) !domain.AgentMemory {
        if (self.agent_memory.isExternal()) return self.agentMemoryStoreRuntime(allocator, input);
        return self.agentMemoryStoreNative(allocator, input);
    }

    pub fn agentMemoryStoreRouted(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput, route: AgentMemoryStorageRoute) !domain.AgentMemory {
        return switch (route.target) {
            .primary => self.agentMemoryStore(allocator, input),
            .native => self.agentMemoryStoreNative(allocator, input),
            .runtime => self.agentMemoryStoreRuntime(allocator, input),
            .named => self.agentMemoryStoreNamed(allocator, input, route),
            .subset => self.agentMemoryStoreSubset(allocator, input, route),
            .all => blk: {
                var result = try self.agentMemoryStoreNative(allocator, input);
                errdefer agent_memory_runtime.freeAgentMemory(allocator, &result);
                if (self.agent_memory.isExternal() and !self.agent_memory.isNoop()) {
                    const next = try self.agentMemoryStoreRuntime(allocator, input);
                    agent_memory_runtime.freeAgentMemory(allocator, &result);
                    result = next;
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    if (named.runtime.isNoop()) continue;
                    const next = try self.agentMemoryStoreInRuntime(allocator, &named.runtime, input, named.name);
                    agent_memory_runtime.freeAgentMemory(allocator, &result);
                    result = next;
                }
                break :blk result;
            },
        };
    }

    fn namedAgentMemoryRuntime(self: *Store, route: AgentMemoryStorageRoute) !*agent_memory_runtime.Runtime {
        const name = route.name orelse return error.AgentMemoryStorageUnavailable;
        return self.agent_memory_stores.get(name) orelse error.AgentMemoryStorageUnavailable;
    }

    fn agentMemoryStoreRuntime(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput) !domain.AgentMemory {
        if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
        return self.agentMemoryStoreInRuntime(allocator, &self.agent_memory, input, "runtime");
    }

    fn agentMemoryStoreNamed(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput, route: AgentMemoryStorageRoute) !domain.AgentMemory {
        const runtime = try self.namedAgentMemoryRuntime(route);
        return self.agentMemoryStoreInRuntime(allocator, runtime, input, route.name orelse "named");
    }

    fn agentMemoryStoreInRuntime(self: *Store, allocator: std.mem.Allocator, runtime: *agent_memory_runtime.Runtime, input: AgentMemoryInput, store_name: []const u8) !domain.AgentMemory {
        var entry = try runtime.store(allocator, .{
            .key = input.key,
            .content = input.content,
            .category = input.category,
            .session_id = input.session_id,
            .scope = input.scope,
            .permissions_json = input.permissions_json,
            .metadata_json = input.metadata_json,
            .actor_id = input.actor_id,
            .writer_actor_id = input.writer_actor_id,
            .operation = input.operation,
        });
        try tagAgentMemoryStore(allocator, &entry, store_name);
        errdefer {
            var cleanup = entry;
            agent_memory_runtime.freeAgentMemory(allocator, &cleanup);
        }
        if (runtime.isNoop()) return entry;
        try self.materializeRuntimeAgentMemory(allocator, entry, store_name);
        if (!input.suppress_feed) try self.appendAgentMemoryFeedEvent(allocator, entry, store_name, input.operation, input.content);
        try self.enqueueAgentMemoryLucidPut(allocator, entry, input.writer_actor_id orelse input.actor_id);
        return entry;
    }

    fn agentMemoryStoreNative(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput) !domain.AgentMemory {
        var entry = try switch (self.backend) {
            .sqlite => |*s| s.agentMemoryStore(allocator, input),
            .postgres => |*p| p.agentMemoryStore(allocator, input),
        };
        try tagAgentMemoryStore(allocator, &entry, "native");
        errdefer {
            var cleanup = entry;
            agent_memory_runtime.freeAgentMemory(allocator, &cleanup);
        }
        if (!input.suppress_feed) try self.appendAgentMemoryFeedEvent(allocator, entry, "native", input.operation, input.content);
        try self.enqueueAgentMemoryLucidPut(allocator, entry, input.writer_actor_id orelse input.actor_id);
        return entry;
    }

    fn materializeRuntimeAgentMemory(self: *Store, allocator: std.mem.Allocator, entry: domain.AgentMemory, store_name: []const u8) !void {
        try self.deprecateRuntimeAgentMemoryMirrors(allocator, store_name, entry.key, entry.session_id, entry.actor_id, if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id);
        const source_title = try std.fmt.allocPrint(allocator, "Runtime agent memory: {s}:{s}", .{ store_name, entry.key });
        defer allocator.free(source_title);
        const metadata = try agentMemoryRuntimeMetadataJson(allocator, store_name, entry);
        defer allocator.free(metadata);
        const source = try self.createRuntimeAgentMemorySource(allocator, .{
            .source_type = "agent_observation",
            .title = source_title,
            .content = entry.content,
            .scope = entry.scope,
            .permissions_json = entry.permissions_json,
            .metadata_json = metadata,
            .actor_id = if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id,
        });
        defer allocator.free(source.id);
        const source_ids = try singleJsonString(allocator, source.id);
        defer allocator.free(source_ids);
        const evidence = try evidenceRangeJson(allocator, source.id, entry.content.len, "agent_memory_runtime");
        defer allocator.free(evidence);
        const atom = try self.createMemoryAtom(allocator, .{
            .predicate = "agent.memory",
            .object = entry.key,
            .text = entry.content,
            .scope = entry.scope,
            .confidence = 0.8,
            .status = domain.defaultMemoryStatus("agent", entry.scope),
            .source_ids_json = source_ids,
            .evidence_ranges_json = evidence,
            .created_by = "agent",
            .permissions_json = entry.permissions_json,
            .tags_json = "[\"agent_memory\",\"runtime\"]",
            .actor_id = if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id,
        });
        defer allocator.free(atom.id);
    }

    fn deprecateRuntimeAgentMemoryMirrors(self: *Store, allocator: std.mem.Allocator, store_name: []const u8, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, writer_actor_id: ?[]const u8) !void {
        return switch (self.backend) {
            .sqlite => |*s| s.deprecateRuntimeAgentMemoryMirrors(store_name, key, session_id, owner_actor_id, writer_actor_id),
            .postgres => |*p| p.deprecateRuntimeAgentMemoryMirrors(allocator, store_name, key, session_id, owner_actor_id, writer_actor_id),
        };
    }

    fn deprecateRuntimeAgentMemoryMirrorsAllSessions(self: *Store, allocator: std.mem.Allocator, store_name: []const u8, key: []const u8, owner_actor_id: []const u8, writer_actor_id: ?[]const u8) !void {
        return switch (self.backend) {
            .sqlite => |*s| s.deprecateRuntimeAgentMemoryMirrorsAllSessions(store_name, key, owner_actor_id, writer_actor_id),
            .postgres => |*p| p.deprecateRuntimeAgentMemoryMirrorsAllSessions(allocator, store_name, key, owner_actor_id, writer_actor_id),
        };
    }

    fn deprecateRuntimeAgentMemoryMirrorsForDelete(self: *Store, key: []const u8, session_id: ?[]const u8, owner_actor_id: ?[]const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const owner = owner_actor_id orelse return;
        switch (route.target) {
            .primary => if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, "runtime", key, session_id, owner, writer_actor_id),
            .native => {},
            .runtime => if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, "runtime", key, session_id, owner, writer_actor_id),
            .named => try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, route.name orelse "named", key, session_id, owner, writer_actor_id),
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| try self.deprecateRuntimeAgentMemoryMirrorsForDelete(key, session_id, owner, writer_actor_id, routeForSubsetStoreName(store_name));
            },
            .all => {
                if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, "runtime", key, session_id, owner, writer_actor_id);
                for (self.agent_memory_stores.stores.items) |named| {
                    try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, named.name, key, session_id, owner, writer_actor_id);
                }
            },
        }
    }

    fn deprecateRuntimeAgentMemoryMirrorsForDeleteAll(self: *Store, key: []const u8, owner_actor_id: ?[]const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const owner = owner_actor_id orelse return;
        switch (route.target) {
            .primary => if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, "runtime", key, owner, writer_actor_id),
            .native => {},
            .runtime => if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, "runtime", key, owner, writer_actor_id),
            .named => try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, route.name orelse "named", key, owner, writer_actor_id),
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| try self.deprecateRuntimeAgentMemoryMirrorsForDeleteAll(key, owner, writer_actor_id, routeForSubsetStoreName(store_name));
            },
            .all => {
                if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, "runtime", key, owner, writer_actor_id);
                for (self.agent_memory_stores.stores.items) |named| {
                    try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, named.name, key, owner, writer_actor_id);
                }
            },
        }
    }

    fn createRuntimeAgentMemorySource(self: *Store, allocator: std.mem.Allocator, input: SourceInput) !domain.Source {
        return switch (self.backend) {
            .sqlite => |*s| s.createSource(allocator, input),
            .postgres => |*p| p.createSource(allocator, input),
        };
    }

    fn appendAgentMemoryFeedEvent(self: *Store, allocator: std.mem.Allocator, entry: domain.AgentMemory, store_name: []const u8, operation: domain.AgentMemoryOperation, operation_content: []const u8) !void {
        if (domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) return;
        const payload = try agentMemoryFeedPayloadJson(allocator, store_name, entry, operation, operation_content);
        defer allocator.free(payload);
        _ = try self.appendFeedEvent(.{
            .event_type = agentMemoryWriteFeedEventType(store_name, operation),
            .operation = operation.name(),
            .object_type = "agent_memory",
            .object_id = entry.id,
            .scope = entry.scope,
            .permissions_json = entry.permissions_json,
            .actor_id = if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id,
            .payload_json = payload,
            .status = "applied",
        });
    }

    fn agentMemoryDeleteRouteStoreName(self: *Store, route: AgentMemoryStorageRoute) []const u8 {
        return switch (route.target) {
            .primary => if (self.agent_memory.isExternal()) "runtime" else "native",
            .native => "native",
            .runtime => "runtime",
            .named => route.name orelse "named",
            .subset, .all => "multiple",
        };
    }

    fn appendAgentMemoryDeleteFeedEvent(self: *Store, allocator: std.mem.Allocator, route: AgentMemoryStorageRoute, key: []const u8, session_id: ?[]const u8, requested_owner_actor_id: ?[]const u8, writer_actor_id: ?[]const u8, existing: ?domain.AgentMemory) !void {
        if (domain.isInternalMemoryKey(key)) return;
        const store_name = self.agentMemoryDeleteRouteStoreName(route);
        const owner_actor_id = requested_owner_actor_id orelse if (existing) |entry| entry.actor_id else return;
        var fallback_scope: ?[]const u8 = null;
        defer if (fallback_scope) |scope| allocator.free(scope);
        const scope = if (existing) |entry| entry.scope else blk: {
            fallback_scope = try agentMemoryScope(allocator, owner_actor_id, session_id, null);
            break :blk fallback_scope.?;
        };
        const permissions_json = if (existing) |entry| entry.permissions_json else "[]";
        const payload = try agentMemoryDeleteFeedPayloadJson(allocator, store_name, key, session_id, owner_actor_id, scope, permissions_json);
        defer allocator.free(payload);
        _ = try self.appendFeedEvent(.{
            .event_type = agentMemoryDeleteFeedEventType(store_name),
            .operation = "delete",
            .object_type = "agent_memory",
            .object_id = key,
            .scope = scope,
            .permissions_json = permissions_json,
            .actor_id = writer_actor_id orelse owner_actor_id,
            .payload_json = payload,
            .status = "applied",
        });
    }

    fn appendAgentMemoryDeleteAllFeedEvent(self: *Store, allocator: std.mem.Allocator, route: AgentMemoryStorageRoute, key: []const u8, requested_owner_actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !void {
        if (domain.isInternalMemoryKey(key)) return;
        const owner_actor_id = requested_owner_actor_id orelse return;
        const store_name = self.agentMemoryDeleteRouteStoreName(route);
        const scope = try agentMemoryScope(allocator, owner_actor_id, null, null);
        defer allocator.free(scope);
        const payload = try agentMemoryDeleteFeedPayloadJson(allocator, store_name, key, null, owner_actor_id, scope, "[]");
        defer allocator.free(payload);
        _ = try self.appendFeedEvent(.{
            .event_type = agentMemoryDeleteAllFeedEventType(store_name),
            .operation = "delete_all",
            .object_type = "agent_memory",
            .object_id = key,
            .scope = scope,
            .permissions_json = "[]",
            .actor_id = writer_actor_id orelse owner_actor_id,
            .payload_json = payload,
            .status = "applied",
        });
    }

    fn appendAppliedPrimitiveFeedEvent(
        self: *Store,
        allocator: std.mem.Allocator,
        event_type: []const u8,
        object_type: []const u8,
        object_id: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
        payload_json: []const u8,
        route: AgentMemoryStorageRoute,
    ) !void {
        const route_part = try storageRouteDedupePart(allocator, route);
        defer allocator.free(route_part);
        const dedupe_key = try std.fmt.allocPrint(allocator, "direct:{s}:{s}:{s}", .{ object_type, route_part, object_id });
        defer allocator.free(dedupe_key);
        const routed_payload = try payloadWithStorageRouteJson(allocator, payload_json, route);
        defer allocator.free(routed_payload);
        _ = try self.appendFeedEvent(.{
            .event_type = event_type,
            .operation = "put",
            .object_type = object_type,
            .object_id = object_id,
            .scope = scope,
            .permissions_json = permissions_json,
            .actor_id = actor_id,
            .dedupe_key = dedupe_key,
            .payload_json = routed_payload,
            .status = "applied",
        });
    }

    fn appendSourcePutFeedEvent(self: *Store, allocator: std.mem.Allocator, source: domain.Source, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const payload = try domainPayloadJson(allocator, source);
        defer allocator.free(payload);
        try self.appendAppliedPrimitiveFeedEvent(allocator, "source.put", "source", source.id, source.scope, source.permissions_json, actor_id, payload, route);
    }

    fn appendArtifactPutFeedEvent(self: *Store, allocator: std.mem.Allocator, artifact: domain.Artifact, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const payload = try domainPayloadJson(allocator, artifact);
        defer allocator.free(payload);
        try self.appendAppliedPrimitiveFeedEvent(allocator, "artifact.put", "artifact", artifact.id, artifact.scope, artifact.permissions_json, actor_id, payload, route);
    }

    fn appendEntityPutFeedEvent(self: *Store, allocator: std.mem.Allocator, entity: domain.Entity, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const payload = try domainPayloadJson(allocator, entity);
        defer allocator.free(payload);
        try self.appendAppliedPrimitiveFeedEvent(allocator, "entity.put", "entity", entity.id, entity.scope, entity.permissions_json, actor_id, payload, route);
    }

    fn appendRelationPutFeedEvent(self: *Store, allocator: std.mem.Allocator, relation: domain.Relation, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const payload = try domainPayloadJson(allocator, relation);
        defer allocator.free(payload);
        try self.appendAppliedPrimitiveFeedEvent(allocator, "relation.put", "relation", relation.id, relation.scope, relation.permissions_json, actor_id, payload, route);
    }

    fn appendMemoryAtomPutFeedEvent(self: *Store, allocator: std.mem.Allocator, atom: domain.MemoryAtom, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const payload = try domainPayloadJson(allocator, atom);
        defer allocator.free(payload);
        try self.appendAppliedPrimitiveFeedEvent(allocator, "memory_atom.put", "memory_atom", atom.id, atom.scope, atom.permissions_json, actor_id, payload, route);
    }

    fn appendContextPackPutFeedEvent(self: *Store, allocator: std.mem.Allocator, pack: ContextPackResult, scope: []const u8, permissions_json: []const u8, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const payload = try contextPackFeedPayloadJson(allocator, pack);
        defer allocator.free(payload);
