        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, space.id);
        bindText(stmt, 2, space.name);
        bindText(stmt, 3, space.title);
        bindText(stmt, 4, space.description orelse "");
        bindText(stmt, 5, space.metadata_json);
