    pub fn getMemoryAtom(self: *Self, allocator: std.mem.Allocator, id: []const u8) !?domain.MemoryAtom {
        const stmt = try self.prepare("SELECT id,subject_entity_id,predicate,object,text,scope,confidence,status,source_ids_json,evidence_ranges_json,created_by,created_at_ms,valid_from_ms,valid_until_ms,last_verified_at_ms,owner,permissions_json,tags_json FROM memory_atoms WHERE id = ?1 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return null;
        const row = try readMemoryAtom(allocator, stmt);
        return row;
    }

    fn readMemoryAtom(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt) !domain.MemoryAtom {
        return .{
            .id = try columnText(allocator, stmt, 0),
            .subject_entity_id = try columnTextNullable(allocator, stmt, 1),
            .predicate = try columnText(allocator, stmt, 2),
            .object = try columnText(allocator, stmt, 3),
            .text = try columnText(allocator, stmt, 4),
            .scope = try columnText(allocator, stmt, 5),
            .confidence = c.sqlite3_column_double(stmt, 6),
            .status = try columnText(allocator, stmt, 7),
            .source_ids_json = try columnText(allocator, stmt, 8),
            .evidence_ranges_json = try columnText(allocator, stmt, 9),
            .created_by = try columnText(allocator, stmt, 10),
            .created_at_ms = c.sqlite3_column_int64(stmt, 11),
            .valid_from_ms = if (c.sqlite3_column_type(stmt, 12) == c.SQLITE_NULL) null else c.sqlite3_column_int64(stmt, 12),
            .valid_until_ms = if (c.sqlite3_column_type(stmt, 13) == c.SQLITE_NULL) null else c.sqlite3_column_int64(stmt, 13),
            .last_verified_at_ms = if (c.sqlite3_column_type(stmt, 14) == c.SQLITE_NULL) null else c.sqlite3_column_int64(stmt, 14),
            .owner = try columnTextNullable(allocator, stmt, 15),
            .permissions_json = try columnText(allocator, stmt, 16),
            .tags_json = try columnText(allocator, stmt, 17),
        };
    }

    pub fn patchMemoryAtomStatus(self: *Self, id: []const u8, status: []const u8, verified: bool) !bool {
        return self.patchMemoryAtomStatusActor(id, status, verified, null);
    }

    pub fn patchMemoryAtomStatusActor(self: *Self, id: []const u8, status: []const u8, verified: bool, actor_id: ?[]const u8) !bool {
        const stmt = try self.prepare("UPDATE memory_atoms SET status = ?1, last_verified_at_ms = CASE WHEN ?2 THEN ?3 ELSE last_verified_at_ms END WHERE id = ?4");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, status);
        _ = c.sqlite3_bind_int(stmt, 2, if (verified) 1 else 0);
        _ = c.sqlite3_bind_int64(stmt, 3, ids.nowMs());
        bindText(stmt, 4, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.UpdateFailed;
        const changed = c.sqlite3_changes(self.db) > 0;
        if (changed) try self.insertAuditActor("memory_atom.status", actor_id, "memory_atom", id);
        return changed;
    }

    pub fn patchArtifactStatusActor(self: *Self, id: []const u8, status: []const u8, actor_id: ?[]const u8) !bool {
        const stmt = try self.prepare("UPDATE artifacts SET status = ?1, updated_at_ms = ?2, last_verified_at_ms = CASE WHEN ?3 THEN ?2 ELSE last_verified_at_ms END WHERE id = ?4");
        defer _ = c.sqlite3_finalize(stmt);
        const now = ids.nowMs();
        bindText(stmt, 1, status);
        _ = c.sqlite3_bind_int64(stmt, 2, now);
        _ = c.sqlite3_bind_int(stmt, 3, if (std.mem.eql(u8, status, "verified") or std.mem.eql(u8, status, "accepted")) 1 else 0);
        bindText(stmt, 4, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.UpdateFailed;
        const changed = c.sqlite3_changes(self.db) > 0;
        if (changed) try self.insertAuditActor("artifact.status", actor_id, "artifact", id);
        return changed;
    }

    pub fn patchRelationStatusActor(self: *Self, id: []const u8, status: []const u8, actor_id: ?[]const u8) !bool {
        const stmt = try self.prepare("UPDATE relations SET status = ?1 WHERE id = ?2");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, status);
        bindText(stmt, 2, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.UpdateFailed;
        const changed = c.sqlite3_changes(self.db) > 0;
        if (changed) try self.insertAuditActor("relation.status", actor_id, "relation", id);
        return changed;
    }

    pub fn patchPrimitiveLifecycleActor(self: *Self, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, status: []const u8, actor_id: ?[]const u8, payload_json: []const u8) !bool {
        if (!primitiveLifecycleUsesOverlay(object_type)) return false;
        if (!try self.primitiveLifecycleTargetExists(allocator, object_type, object_id)) return false;
        const now = ids.nowMs();
        const stmt = try self.prepare(
            "INSERT INTO primitive_lifecycle (object_type,object_id,status,actor_id,payload_json,updated_at_ms) VALUES (?1,?2,?3,?4,?5,?6) " ++
                "ON CONFLICT(object_type, object_id) DO UPDATE SET status=excluded.status, actor_id=excluded.actor_id, payload_json=excluded.payload_json, updated_at_ms=excluded.updated_at_ms",
        );
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, object_type);
        bindText(stmt, 2, object_id);
        bindText(stmt, 3, status);
        bindNullableText(stmt, 4, actor_id);
        bindText(stmt, 5, payload_json);
        _ = c.sqlite3_bind_int64(stmt, 6, now);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.UpdateFailed;
        try self.insertAuditActor("primitive_lifecycle.status", actor_id, object_type, object_id);
        return true;
    }

    pub fn primitiveLifecycleStatus(self: *Self, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8) ![]const u8 {
        if (!primitiveLifecycleUsesOverlay(object_type)) return "active";
        const stmt = try self.prepare("SELECT status FROM primitive_lifecycle WHERE object_type = ?1 AND object_id = ?2 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, object_type);
        bindText(stmt, 2, object_id);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return "active";
        return try columnText(allocator, stmt, 0);
    }

    fn primitiveLifecycleTargetExists(self: *Self, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8) !bool {
        if (std.mem.eql(u8, object_type, "source")) return (try self.getSource(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "entity")) return (try self.getEntity(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "context_pack")) return try self.contextPackExists(object_id);
        if (std.mem.eql(u8, object_type, "space")) return (try self.getSpace(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "policy_scope")) return (try self.getPolicyScope(allocator, object_id)) != null;
        return false;
    }

    fn contextPackExists(self: *Self, id: []const u8) !bool {
        const stmt = try self.prepare("SELECT 1 FROM context_packs WHERE id = ?1 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        return c.sqlite3_step(stmt) == c.SQLITE_ROW;
    }

    pub fn contextPackById(self: *Self, allocator: std.mem.Allocator, id: []const u8) !?ContextPackResult {
        const stmt = try self.prepare("SELECT id,purpose,target,query_text,included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated,generated_summary,token_budget,created_at_ms FROM context_packs WHERE id = ?1 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return null;
        return try readSqliteContextPackResult(allocator, stmt);
    }

    fn readSqliteContextPackResult(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt) !ContextPackResult {
        const sources = try columnText(allocator, stmt, 4);
        return .{
            .id = try columnText(allocator, stmt, 0),
            .purpose = try columnText(allocator, stmt, 1),
            .target = try columnText(allocator, stmt, 2),
            .query = try columnText(allocator, stmt, 3),
            .generated_summary = try columnText(allocator, stmt, 11),
            .sections_json = "{}",
            .citations_json = try allocator.dupe(u8, sources),
            .forbidden_assumptions_json = context_pack.forbidden_assumptions_json,
            .suggested_next_steps_json = context_pack.suggested_next_steps_json,
            .included_sources_json = sources,
            .included_artifacts_json = try columnText(allocator, stmt, 5),
            .included_memory_atoms_json = try columnText(allocator, stmt, 6),
            .included_result_refs_json = try columnText(allocator, stmt, 7),
            .required_scopes_json = try columnText(allocator, stmt, 8),
            .actor_id = try columnTextNullable(allocator, stmt, 9),
            .actor_isolated = c.sqlite3_column_int(stmt, 10) != 0,
            .token_budget = c.sqlite3_column_int64(stmt, 12),
            .created_at_ms = c.sqlite3_column_int64(stmt, 13),
            .persisted = true,
        };
    }

    pub fn contextPackLifecycleTarget(self: *Self, allocator: std.mem.Allocator, id: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !?PrimitiveLifecycleTarget {
        const stmt = try self.prepare("SELECT included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated FROM context_packs WHERE id = ?1 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return null;
        const sources = try columnText(allocator, stmt, 0);
        const artifacts = try columnText(allocator, stmt, 1);
        const atoms = try columnText(allocator, stmt, 2);
        const refs = try columnText(allocator, stmt, 3);
        const required_scopes = try columnText(allocator, stmt, 4);
        const row_actor_id = try columnTextNullable(allocator, stmt, 5);
        const actor_isolated = c.sqlite3_column_int(stmt, 6) != 0;
        if (!try self.contextPackVisible(allocator, sources, artifacts, atoms, refs, required_scopes, row_actor_id, actor_isolated, scopes_json, actor_id, true)) return null;
        return .{
            .object_id = try allocator.dupe(u8, id),
            .scope = try lifecycleScopeFromRequiredScopesJson(allocator, required_scopes),
            .permissions_json = required_scopes,
        };
    }

    pub fn search(self: *Self, allocator: std.mem.Allocator, input: SearchInput) ![]domain.SearchResult {
        const limit = @max(@as(usize, 1), @min(input.limit, 100));
        var plan = try retrieval_mod.buildPlanWithAdaptive(allocator, input.query, input.use_vector, input.allow_reranker, .{ .enabled = input.adaptive_retrieval });
        defer plan.deinit(allocator);
        var keyword_input = input;
        keyword_input.query = plan.keyword_query;
        const fts_query = try retrieval_mod.buildFts5Query(allocator, keyword_input.query);
        defer allocator.free(fts_query);
        const use_fts = fts_query.len > 0;
        const exact_graph_query = retrieval_mod.queryHasEntityHint(input.query);
        const graph_input = if (exact_graph_query) input else keyword_input;
        const graph_fts_query = if (exact_graph_query) try retrieval_mod.buildFts5Query(allocator, input.query) else fts_query;
        defer if (exact_graph_query) allocator.free(graph_fts_query);
        const use_graph_fts = graph_fts_query.len > 0;
        var keyword_results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        errdefer keyword_results.deinit(allocator);

        if (plan.use_keyword) {
            try self.searchMemoryAtoms(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            try self.searchSpaces(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            try self.searchPolicyScopes(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            try self.searchSources(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            try self.searchArtifacts(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            try self.searchEntities(allocator, graph_input, graph_fts_query, use_graph_fts, &keyword_results);
            try self.searchRelations(allocator, graph_input, graph_fts_query, use_graph_fts, &keyword_results);
            try self.searchContextPacks(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            try self.searchFeedEvents(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            try self.searchAgentMemories(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            if (input.include_sessions) {
                try self.searchSessionMessages(allocator, keyword_input, fts_query, use_fts, &keyword_results);
            }
            if (keyword_results.items.len == 0 and use_fts) {
                try self.searchMemoryAtoms(allocator, keyword_input, "", false, &keyword_results);
                try self.searchSpaces(allocator, keyword_input, "", false, &keyword_results);
                try self.searchPolicyScopes(allocator, keyword_input, "", false, &keyword_results);
                try self.searchSources(allocator, keyword_input, "", false, &keyword_results);
                try self.searchArtifacts(allocator, keyword_input, "", false, &keyword_results);
                try self.searchEntities(allocator, graph_input, "", false, &keyword_results);
                try self.searchRelations(allocator, graph_input, "", false, &keyword_results);
                try self.searchContextPacks(allocator, keyword_input, "", false, &keyword_results);
                try self.searchFeedEvents(allocator, keyword_input, "", false, &keyword_results);
                try self.searchAgentMemories(allocator, keyword_input, "", false, &keyword_results);
                if (input.include_sessions) try self.searchSessionMessages(allocator, keyword_input, "", false, &keyword_results);
            }
        }

        sortSearchResults(keyword_results.items);

        var vector_results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        errdefer vector_results.deinit(allocator);
        if (plan.use_vector and input.query.len > 0) {
            try self.searchVectorCandidates(allocator, input, plan.expanded_query, &vector_results);
        }
        if (plan.use_graph or keyword_results.items.len > 0) {
            try self.expandGraphCandidates(allocator, input, &keyword_results);
        }

        const final = try self.fuseSearchResults(allocator, input, keyword_results.items, vector_results.items, limit);
        return final;
    }

    fn recordVisibleWithPolicy(self: *Self, allocator: std.mem.Allocator, scope: []const u8, permissions_json: []const u8, scopes_json: []const u8) !bool {
        if (!domain.recordVisible(scope, permissions_json, scopes_json)) return false;
        const policy = try self.getPolicyScope(allocator, scope);
        if (policy) |p| return domain.recordVisible(p.scope, p.permissions_json, scopes_json);
        return true;
    }

    fn recordVisibleWithPolicyForActor(self: *Self, allocator: std.mem.Allocator, scope: []const u8, permissions_json: []const u8, scopes_json: []const u8, actor_id: ?[]const u8) !bool {
        if (try self.recordVisibleWithPolicy(allocator, scope, permissions_json, scopes_json)) return true;
        const actor = actor_id orelse return false;
        if (!permissionsVisibleForActor(allocator, permissions_json, scopes_json, actor)) return false;
        if (!domain.scopeVisible(scope, scopes_json) and !domain.isActorOwnedAgentMemoryScope(scope, actor)) return false;
        const policy = try self.getPolicyScope(allocator, scope);
        if (policy) |p| return domain.recordVisible(p.scope, p.permissions_json, scopes_json);
        return true;
    }

    fn searchMemoryAtoms(self: *Self, allocator: std.mem.Allocator, input: SearchInput, fts_query: []const u8, use_fts: bool, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        const stmt = if (use_fts)
            try self.prepare("SELECT ma.id,ma.text,ma.scope,ma.status,ma.confidence,ma.source_ids_json,ma.created_at_ms,ma.permissions_json,ma.predicate,bm25(memory_atoms_fts) FROM memory_atoms_fts JOIN memory_atoms ma ON ma.id = memory_atoms_fts.id WHERE memory_atoms_fts MATCH ?1 ORDER BY bm25(memory_atoms_fts)")
        else
            try self.prepare("SELECT id,text,scope,status,confidence,source_ids_json,created_at_ms,permissions_json,predicate,0 FROM memory_atoms ORDER BY created_at_ms DESC");
        defer _ = c.sqlite3_finalize(stmt);
        if (use_fts) bindText(stmt, 1, fts_query);
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const id_text = try columnText(allocator, stmt, 0);
            const text = try columnText(allocator, stmt, 1);
            const scope = try columnText(allocator, stmt, 2);
            const status = try columnText(allocator, stmt, 3);
            const confidence = c.sqlite3_column_double(stmt, 4);
            const source_ids = try columnText(allocator, stmt, 5);
            const created_at_ms = c.sqlite3_column_int64(stmt, 6);
            const permissions = try columnText(allocator, stmt, 7);
            const predicate = try columnText(allocator, stmt, 8);
            if (std.mem.eql(u8, predicate, "agent.memory")) continue;
            if (!input.include_deprecated and !domain.isDefaultVisibleStatus(status)) continue;
            if (!try self.recordVisibleWithPolicyForActor(allocator, scope, permissions, input.scopes_json, input.actor_id)) continue;
            const relevance = if (use_fts) @max(0.0, 10.0 - c.sqlite3_column_double(stmt, 9)) else scoreText(input.query, text);
            if (!use_fts and relevance <= 0 and input.query.len > 0) continue;
            const citations = try self.sanitizeSourceIdsForActor(allocator, source_ids, input.scopes_json, input.actor_id);
            try results.append(allocator, .{
                .id = id_text,
                .result_type = "memory_atom",
                .title = id_text,
                .text = text,
                .scope = scope,
                .status = status,
                .score = relevance + confidence,
                .source_ids_json = citations,
                .required_scopes_json = try requiredAccessJsonGlobal(allocator, scope, permissions, input.actor_id),
                .actor_isolated = resultActorIsolatedGlobal(allocator, "memory_atom", scope, permissions, input.actor_id),
                .created_at_ms = created_at_ms,
                .confidence = confidence,
            });
        }
    }

    fn searchSpaces(self: *Self, allocator: std.mem.Allocator, input: SearchInput, fts_query: []const u8, use_fts: bool, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        const stmt = if (use_fts)
            try self.prepare("SELECT s.id,s.name,s.title,s.description,s.scope,s.permissions_json,s.metadata_json,s.updated_at_ms,bm25(spaces_fts) FROM spaces_fts JOIN spaces s ON s.id = spaces_fts.id WHERE spaces_fts MATCH ?1 ORDER BY bm25(spaces_fts)")
        else
            try self.prepare("SELECT id,name,title,description,scope,permissions_json,metadata_json,updated_at_ms FROM spaces ORDER BY updated_at_ms DESC");
        defer _ = c.sqlite3_finalize(stmt);
        if (use_fts) bindText(stmt, 1, fts_query);
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const id_text = try columnText(allocator, stmt, 0);
            const name = try columnText(allocator, stmt, 1);
            const title = try columnText(allocator, stmt, 2);
            const description = try columnTextNullable(allocator, stmt, 3);
            const scope = try columnText(allocator, stmt, 4);
            const permissions = try columnText(allocator, stmt, 5);
            const metadata = try columnText(allocator, stmt, 6);
            const updated_at_ms = c.sqlite3_column_int64(stmt, 7);
            if (!try self.recordVisibleWithPolicyForActor(allocator, scope, permissions, input.scopes_json, input.actor_id)) continue;
            const status = try self.primitiveLifecycleStatus(allocator, "space", id_text);
            if (!input.include_deprecated and !domain.isDefaultVisibleStatus(status)) continue;
            const text = if (description) |d| try std.fmt.allocPrint(allocator, "{s} {s} {s} {s}", .{ name, title, d, metadata }) else try std.fmt.allocPrint(allocator, "{s} {s} {s}", .{ name, title, metadata });
            const relevance = if (use_fts) @max(0.0, 6.0 - c.sqlite3_column_double(stmt, 8)) else scoreText(input.query, text);
            if (!use_fts and input.query.len > 0 and relevance <= 0) continue;
            try results.append(allocator, .{ .id = id_text, .result_type = "space", .title = title, .text = text, .scope = scope, .status = status, .score = relevance + 0.2, .source_ids_json = "[]", .required_scopes_json = try requiredAccessJsonGlobal(allocator, scope, permissions, input.actor_id), .actor_isolated = resultActorIsolatedGlobal(allocator, "space", scope, permissions, input.actor_id), .created_at_ms = updated_at_ms, .confidence = 0.7 });
        }
    }

    fn searchPolicyScopes(self: *Self, allocator: std.mem.Allocator, input: SearchInput, fts_query: []const u8, use_fts: bool, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        const stmt = if (use_fts)
            try self.prepare("SELECT p.scope,p.visibility,p.permissions_json,p.owner,p.metadata_json,p.updated_at_ms,bm25(policy_scopes_fts) FROM policy_scopes_fts JOIN policy_scopes p ON p.scope = policy_scopes_fts.scope WHERE policy_scopes_fts MATCH ?1 ORDER BY bm25(policy_scopes_fts)")
        else
            try self.prepare("SELECT scope,visibility,permissions_json,owner,metadata_json,updated_at_ms FROM policy_scopes ORDER BY updated_at_ms DESC");
        defer _ = c.sqlite3_finalize(stmt);
        if (use_fts) bindText(stmt, 1, fts_query);
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const scope = try columnText(allocator, stmt, 0);
            const visibility = try columnText(allocator, stmt, 1);
            const permissions = try columnText(allocator, stmt, 2);
            const owner = try columnTextNullable(allocator, stmt, 3);
            const metadata = try columnText(allocator, stmt, 4);
            const updated_at_ms = c.sqlite3_column_int64(stmt, 5);
            if (!try self.recordVisibleWithPolicyForActor(allocator, scope, permissions, input.scopes_json, input.actor_id)) continue;
            const status = try self.primitiveLifecycleStatus(allocator, "policy_scope", scope);
            if (!input.include_deprecated and !domain.isDefaultVisibleStatus(status)) continue;
            const text = if (owner) |o| try std.fmt.allocPrint(allocator, "{s} {s} {s} {s}", .{ scope, visibility, o, metadata }) else try std.fmt.allocPrint(allocator, "{s} {s} {s}", .{ scope, visibility, metadata });
            const relevance = if (use_fts) @max(0.0, 6.0 - c.sqlite3_column_double(stmt, 6)) else scoreText(input.query, text);
            if (!use_fts and input.query.len > 0 and relevance <= 0) continue;
            try results.append(allocator, .{ .id = scope, .result_type = "policy_scope", .title = scope, .text = text, .scope = scope, .status = status, .score = relevance + 0.2, .source_ids_json = "[]", .required_scopes_json = try requiredAccessJsonGlobal(allocator, scope, permissions, input.actor_id), .actor_isolated = resultActorIsolatedGlobal(allocator, "policy_scope", scope, permissions, input.actor_id), .created_at_ms = updated_at_ms, .confidence = 0.7 });
        }
    }

    fn searchSources(self: *Self, allocator: std.mem.Allocator, input: SearchInput, fts_query: []const u8, use_fts: bool, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        const stmt = if (use_fts)
            try self.prepare("SELECT s.id,s.title,s.content,s.scope,s.permissions_json,s.imported_at_ms,s.metadata_json,bm25(sources_fts) FROM sources_fts JOIN sources s ON s.id = sources_fts.id WHERE sources_fts MATCH ?1 ORDER BY bm25(sources_fts)")
        else
            try self.prepare("SELECT id,title,content,scope,permissions_json,imported_at_ms,metadata_json,0 FROM sources ORDER BY imported_at_ms DESC");
        defer _ = c.sqlite3_finalize(stmt);
        if (use_fts) bindText(stmt, 1, fts_query);
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const id_text = try columnText(allocator, stmt, 0);
            const title = try columnText(allocator, stmt, 1);
            const content = try columnText(allocator, stmt, 2);
            const scope = try columnText(allocator, stmt, 3);
            const permissions = try columnText(allocator, stmt, 4);
            const imported_at_ms = c.sqlite3_column_int64(stmt, 5);
            const metadata = try columnText(allocator, stmt, 6);
            if (isAgentMemorySourceMetadata(metadata)) continue;
            const status = try self.primitiveLifecycleStatus(allocator, "source", id_text);
            if (!input.include_deprecated and !domain.isDefaultVisibleStatus(status)) continue;
            if (!try self.recordVisibleWithPolicyForActor(allocator, scope, permissions, input.scopes_json, input.actor_id)) continue;
