            try list.append(allocator, try readAgentMemory(allocator, stmt));
        }
        return list.toOwnedSlice(allocator);
    }

    pub fn agentMemorySearch(self: *Self, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        if (limit == 0) return try allocator.alloc(domain.AgentMemory, 0);
        const capped = @max(@as(usize, 1), @min(limit, 100));
        const request_actor = actor_id orelse return try allocator.alloc(domain.AgentMemory, 0);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        const fts_query = try retrieval_mod.buildFts5Query(allocator, query);
        defer allocator.free(fts_query);
        if (fts_query.len > 0) {
            const stmt = try self.prepare(
                "SELECT ami.id, ami.key, ma.text, ami.category, ami.timestamp_ms, ami.session_id, ma.confidence, ami.actor_id, ami.writer_actor_id, ami.scope, ami.permissions_json, bm25(agent_memory_fts) " ++
                    "FROM agent_memory_fts JOIN agent_memory_items ami ON ami.id = agent_memory_fts.id JOIN memory_atoms ma ON ma.id = ami.memory_atom_id " ++
                    "WHERE agent_memory_fts MATCH ?1 " ++
                    "ORDER BY bm25(agent_memory_fts)",
            );
            defer _ = c.sqlite3_finalize(stmt);
            bindText(stmt, 1, fts_query);
            while (c.sqlite3_step(stmt) == c.SQLITE_ROW and out.items.len < capped) {
                if (!try self.agentMemoryStmtVisible(allocator, stmt, scopes_json, request_actor)) continue;
                var entry = try readAgentMemory(allocator, stmt);
                var entry_owned = true;
                defer if (entry_owned) agent_memory_runtime.freeAgentMemory(allocator, &entry);
                if (domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) continue;
                entry.score = @max(0.0, 8.0 - c.sqlite3_column_double(stmt, 11));
                if (session_id) |expected| {
                    if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, expected)) continue;
                } else if (entry.session_id != null) {
                    continue;
                }
                try out.append(allocator, entry);
                entry_owned = false;
            }
            return out.toOwnedSlice(allocator);
        }
        const all = try self.agentMemoryListVisible(allocator, null, session_id, request_actor, scopes_json);
        defer {
            for (all) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
            allocator.free(all);
        }
        for (all) |*entry| {
            const score = scoreText(query, entry.key) + scoreText(query, entry.content);
            if (score <= 0 and query.len > 0) continue;
            entry.score = score + 0.5;
            try out.append(allocator, entry.*);
            detachAgentMemoryResult(entry);
        }
        sortAgentMemoryResults(out.items);
        trimAgentMemoryResults(allocator, &out, capped);
        return out.toOwnedSlice(allocator);
    }

    pub fn agentMemoryDelete(self: *Self, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        self.tx_mutex.lockUncancelable(compat.io());
        defer self.tx_mutex.unlock(compat.io());
        try self.exec("BEGIN IMMEDIATE");
        errdefer self.exec("ROLLBACK") catch {};
        const changed = try self.agentMemoryDeleteInTx(key, session_id, actor_id, writer_actor_id);
        try self.exec("COMMIT");
        return changed;
    }

    pub fn agentMemoryDeleteAll(self: *Self, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        self.tx_mutex.lockUncancelable(compat.io());
        defer self.tx_mutex.unlock(compat.io());
        try self.exec("BEGIN IMMEDIATE");
        errdefer self.exec("ROLLBACK") catch {};
        const changed = try self.agentMemoryDeleteAllInTx(key, actor_id, writer_actor_id);
        try self.exec("COMMIT");
        return changed;
    }

    fn agentMemoryDeleteInTx(self: *Self, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        const audit_actor = writer_actor_id orelse actor_id;
        {
            const stmt = try self.prepare("SELECT memory_atom_id,id FROM agent_memory_items WHERE key = ?1 AND " ++ sqlite_agent_session_actor_where);
            defer _ = c.sqlite3_finalize(stmt);
            bindText(stmt, 1, key);
            bindNullableText(stmt, 2, session_id);
            bindNullableText(stmt, 3, actor_id);
            while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
                const id_text = try columnText(self.allocator, stmt, 0);
                defer self.allocator.free(id_text);
                _ = try self.patchMemoryAtomStatusActor(id_text, "deprecated", false, audit_actor);
                const item_id = try columnText(self.allocator, stmt, 1);
                defer self.allocator.free(item_id);
                try self.deleteFtsRow("agent_memory_fts", item_id);
            }
        }
        const del = try self.prepare("DELETE FROM agent_memory_items WHERE key = ?1 AND " ++ sqlite_agent_session_actor_where);
        defer _ = c.sqlite3_finalize(del);
        bindText(del, 1, key);
        bindNullableText(del, 2, session_id);
        bindNullableText(del, 3, actor_id);
        if (c.sqlite3_step(del) != c.SQLITE_DONE) return error.DeleteFailed;
        const changed = c.sqlite3_changes(self.db) > 0;
        if (changed) try self.insertAuditActor("agent_memory.deleted", audit_actor, "agent_memory", key);
        return changed;
    }

    fn agentMemoryDeleteAllInTx(self: *Self, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        const owner_actor = actor_id orelse return false;
        const audit_actor = writer_actor_id orelse owner_actor;
        {
            const stmt = try self.prepare("SELECT memory_atom_id,id FROM agent_memory_items WHERE key = ?1 AND actor_id = ?2");
            defer _ = c.sqlite3_finalize(stmt);
            bindText(stmt, 1, key);
            bindText(stmt, 2, owner_actor);
            while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
                const id_text = try columnText(self.allocator, stmt, 0);
                defer self.allocator.free(id_text);
                _ = try self.patchMemoryAtomStatusActor(id_text, "deprecated", false, audit_actor);
                const item_id = try columnText(self.allocator, stmt, 1);
                defer self.allocator.free(item_id);
                try self.deleteFtsRow("agent_memory_fts", item_id);
            }
        }
        const del = try self.prepare("DELETE FROM agent_memory_items WHERE key = ?1 AND actor_id = ?2");
        defer _ = c.sqlite3_finalize(del);
        bindText(del, 1, key);
        bindText(del, 2, owner_actor);
        if (c.sqlite3_step(del) != c.SQLITE_DONE) return error.DeleteFailed;
        const changed = c.sqlite3_changes(self.db) > 0;
        if (changed) try self.insertAuditActor("agent_memory.deleted_all", audit_actor, "agent_memory", key);
        return changed;
    }

    pub fn agentMemoryCount(self: *Self, actor_id: ?[]const u8, scopes_json: []const u8) !usize {
        const stmt = try self.prepare("SELECT session_id,actor_id,scope,permissions_json FROM agent_memory_items");
        defer _ = c.sqlite3_finalize(stmt);
        var count: usize = 0;
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const session_id = try columnTextNullable(self.allocator, stmt, 0);
            defer if (session_id) |sid| self.allocator.free(sid);
            const row_actor_id = try columnTextNullable(self.allocator, stmt, 1);
            defer if (row_actor_id) |id_text| self.allocator.free(id_text);
            if (row_actor_id == null or row_actor_id.?.len == 0) continue;
            const scope = try columnText(self.allocator, stmt, 2);
            defer self.allocator.free(scope);
            const permissions = try columnText(self.allocator, stmt, 3);
            defer self.allocator.free(permissions);
            if (!try self.agentMemoryResultVisible(self.allocator, row_actor_id.?, scope, permissions, session_id, scopes_json, actor_id)) continue;
            count += 1;
        }
        return count;
    }

    fn agentMemorySelectSql(comptime extra_where: []const u8, comptime tail: []const u8) [*:0]const u8 {
        return "SELECT ami.id, ami.key, ma.text, ami.category, ami.timestamp_ms, ami.session_id, ma.confidence, ami.actor_id, ami.writer_actor_id, ami.scope, ami.permissions_json " ++
            "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id " ++
            "WHERE " ++ sqlite_agent_session_actor_where_ami ++ " " ++ extra_where ++ " " ++ tail;
    }

    fn agentMemoryVisibleSelectSql(comptime extra_where: []const u8, comptime tail: []const u8) [*:0]const u8 {
        return "SELECT ami.id, ami.key, ma.text, ami.category, ami.timestamp_ms, ami.session_id, ma.confidence, ami.actor_id, ami.writer_actor_id, ami.scope, ami.permissions_json " ++
            "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id " ++
            "WHERE " ++ sqlite_agent_session_where_ami ++ " " ++ extra_where ++ " " ++ tail;
    }

    fn agentMemoryStmtVisible(self: *Self, allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt, scopes_json: []const u8, actor_id: []const u8) !bool {
        const session_id = try columnTextNullable(allocator, stmt, 5);
        defer if (session_id) |sid| allocator.free(sid);
        const owner_actor_id = try columnText(allocator, stmt, 7);
        defer allocator.free(owner_actor_id);
        const scope = try columnText(allocator, stmt, 9);
        defer allocator.free(scope);
        const permissions = try columnText(allocator, stmt, 10);
        defer allocator.free(permissions);
        return try self.agentMemoryResultVisible(allocator, owner_actor_id, scope, permissions, session_id, scopes_json, actor_id);
    }

    fn readAgentMemory(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt) !domain.AgentMemory {
        const timestamp = try std.fmt.allocPrint(allocator, "{d}", .{c.sqlite3_column_int64(stmt, 4)});
        return .{
            .id = try columnText(allocator, stmt, 0),
            .key = try columnText(allocator, stmt, 1),
            .content = try columnText(allocator, stmt, 2),
            .category = try columnText(allocator, stmt, 3),
            .timestamp = timestamp,
            .session_id = try columnTextNullable(allocator, stmt, 5),
            .score = c.sqlite3_column_double(stmt, 6),
            .actor_id = try columnText(allocator, stmt, 7),
            .writer_actor_id = try columnText(allocator, stmt, 8),
            .scope = try columnText(allocator, stmt, 9),
            .permissions_json = try columnText(allocator, stmt, 10),
        };
    }

    pub fn saveMessage(self: *Self, session_id: []const u8, role: []const u8, content: []const u8, actor_id: ?[]const u8) !void {
        return self.saveMessageAt(session_id, role, content, ids.nowMs(), actor_id);
    }

    pub fn saveMessageAt(self: *Self, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8) !void {
        const actor = try requiredActorId(actor_id);
        const stmt = try self.prepare("INSERT INTO session_messages (session_id, actor_id, role, content, created_at_ms) VALUES (?1,?2,?3,?4,?5)");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, session_id);
        bindText(stmt, 2, actor);
        bindText(stmt, 3, role);
        bindText(stmt, 4, content);
        _ = c.sqlite3_bind_int64(stmt, 5, created_at_ms);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
        var id_buf: [32]u8 = undefined;
        const id_text = try std.fmt.bufPrint(&id_buf, "{d}", .{c.sqlite3_last_insert_rowid(self.db)});
        try self.upsertSessionMessageFts(id_text, session_id, role, content);
    }

    pub fn loadMessages(self: *Self, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8) ![]Message {
        const stmt = try self.prepare("SELECT role, content, created_at_ms FROM session_messages WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2) ORDER BY id ASC");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, session_id);
        bindNullableText(stmt, 2, actor_id);
        var out: std.ArrayListUnmanaged(Message) = .empty;
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            try out.append(allocator, .{ .role = try columnText(allocator, stmt, 0), .content = try columnText(allocator, stmt, 1), .created_at_ms = c.sqlite3_column_int64(stmt, 2) });
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn clearMessages(self: *Self, session_id: []const u8, actor_id: ?[]const u8) !void {
        const fts = try self.prepare("DELETE FROM session_messages_fts WHERE id IN (SELECT CAST(id AS TEXT) FROM session_messages WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2))");
        defer _ = c.sqlite3_finalize(fts);
        bindText(fts, 1, session_id);
        bindNullableText(fts, 2, actor_id);
        if (c.sqlite3_step(fts) != c.SQLITE_DONE) return error.DeleteFailed;
        const stmt = try self.prepare("DELETE FROM session_messages WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2)");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, session_id);
        bindNullableText(stmt, 2, actor_id);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.DeleteFailed;
        const usage = try self.prepare("DELETE FROM session_usage WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2)");
        defer _ = c.sqlite3_finalize(usage);
        bindText(usage, 1, session_id);
        bindNullableText(usage, 2, actor_id);
        _ = c.sqlite3_step(usage);
    }

    pub fn clearAutoSaved(self: *Self, session_id: ?[]const u8, actor_id: ?[]const u8) !void {
        if (session_id) |sid| {
            const fts = try self.prepare("DELETE FROM session_messages_fts WHERE id IN (SELECT CAST(id AS TEXT) FROM session_messages WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2) AND (role = 'autosave_user' OR role = 'autosave_assistant'))");
            defer _ = c.sqlite3_finalize(fts);
            bindText(fts, 1, sid);
            bindNullableText(fts, 2, actor_id);
            if (c.sqlite3_step(fts) != c.SQLITE_DONE) return error.DeleteFailed;
            const stmt = try self.prepare("DELETE FROM session_messages WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2) AND (role = 'autosave_user' OR role = 'autosave_assistant')");
            defer _ = c.sqlite3_finalize(stmt);
            bindText(stmt, 1, sid);
            bindNullableText(stmt, 2, actor_id);
            if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.DeleteFailed;
            return;
        }
        const fts = try self.prepare("DELETE FROM session_messages_fts WHERE id IN (SELECT CAST(id AS TEXT) FROM session_messages WHERE (?1 IS NULL OR actor_id = ?1) AND (role = 'autosave_user' OR role = 'autosave_assistant'))");
        defer _ = c.sqlite3_finalize(fts);
        bindNullableText(fts, 1, actor_id);
        if (c.sqlite3_step(fts) != c.SQLITE_DONE) return error.DeleteFailed;
        const stmt = try self.prepare("DELETE FROM session_messages WHERE (?1 IS NULL OR actor_id = ?1) AND (role = 'autosave_user' OR role = 'autosave_assistant')");
        defer _ = c.sqlite3_finalize(stmt);
        bindNullableText(stmt, 1, actor_id);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.DeleteFailed;
    }

    pub fn saveUsage(self: *Self, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8) !void {
        const actor = try requiredActorId(actor_id);
        const stmt = try self.prepare("INSERT INTO session_usage (session_id,actor_id,total_tokens,updated_at_ms) VALUES (?1,?2,?3,?4) ON CONFLICT(session_id, actor_id) DO UPDATE SET total_tokens = excluded.total_tokens, updated_at_ms = excluded.updated_at_ms");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, session_id);
        bindText(stmt, 2, actor);
        _ = c.sqlite3_bind_int64(stmt, 3, @intCast(total_tokens));
        _ = c.sqlite3_bind_int64(stmt, 4, ids.nowMs());
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.UpdateFailed;
    }

    pub fn deleteUsage(self: *Self, session_id: []const u8, actor_id: ?[]const u8) !bool {
        const stmt = try self.prepare("DELETE FROM session_usage WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2)");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, session_id);
        bindNullableText(stmt, 2, actor_id);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.DeleteFailed;
        return c.sqlite3_changes(self.db) > 0;
    }

    pub fn loadUsage(self: *Self, session_id: []const u8, actor_id: ?[]const u8) !?u64 {
        const stmt = try self.prepare("SELECT total_tokens FROM session_usage WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2) ORDER BY CASE WHEN ?2 IS NOT NULL AND actor_id = ?2 THEN 0 ELSE 1 END LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, session_id);
        bindNullableText(stmt, 2, actor_id);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return null;
        return @intCast(c.sqlite3_column_int64(stmt, 0));
    }

    pub fn listSessions(self: *Self, allocator: std.mem.Allocator, limit: usize, offset: usize, actor_id: ?[]const u8) !HistoryList {
        const count_stmt = try self.prepare("SELECT COUNT(*) FROM (SELECT session_id FROM session_messages WHERE (?1 IS NULL OR actor_id = ?1) AND " ++ sqlite_session_history_visible_where ++ " GROUP BY session_id)");
        defer _ = c.sqlite3_finalize(count_stmt);
        bindNullableText(count_stmt, 1, actor_id);
        var total: u64 = 0;
        if (c.sqlite3_step(count_stmt) == c.SQLITE_ROW) total = @intCast(c.sqlite3_column_int64(count_stmt, 0));
        const stmt = try self.prepare("SELECT session_id, COUNT(*), MIN(created_at_ms), MAX(created_at_ms) FROM session_messages WHERE (?1 IS NULL OR actor_id = ?1) AND " ++ sqlite_session_history_visible_where ++ " GROUP BY session_id ORDER BY MAX(created_at_ms) DESC LIMIT ?2 OFFSET ?3");
        defer _ = c.sqlite3_finalize(stmt);
        bindNullableText(stmt, 1, actor_id);
        _ = c.sqlite3_bind_int64(stmt, 2, @intCast(limit));
        _ = c.sqlite3_bind_int64(stmt, 3, @intCast(offset));
        var sessions: std.ArrayListUnmanaged(SessionInfo) = .empty;
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            try sessions.append(allocator, .{
                .session_id = try columnText(allocator, stmt, 0),
                .message_count = @intCast(c.sqlite3_column_int64(stmt, 1)),
                .first_message_at = c.sqlite3_column_int64(stmt, 2),
                .last_message_at = c.sqlite3_column_int64(stmt, 3),
            });
        }
        return .{ .total = total, .sessions = try sessions.toOwnedSlice(allocator) };
    }

    pub fn history(self: *Self, allocator: std.mem.Allocator, session_id: []const u8, limit: usize, offset: usize, actor_id: ?[]const u8) !HistoryShow {
        const count_stmt = try self.prepare("SELECT COUNT(*) FROM session_messages WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2) AND " ++ sqlite_session_history_visible_where);
        defer _ = c.sqlite3_finalize(count_stmt);
        bindText(count_stmt, 1, session_id);
        bindNullableText(count_stmt, 2, actor_id);
        var total: u64 = 0;
        if (c.sqlite3_step(count_stmt) == c.SQLITE_ROW) total = @intCast(c.sqlite3_column_int64(count_stmt, 0));

        const stmt = try self.prepare("SELECT role, content, created_at_ms FROM session_messages WHERE session_id = ?1 AND (?2 IS NULL OR actor_id = ?2) AND " ++ sqlite_session_history_visible_where ++ " ORDER BY id ASC LIMIT ?3 OFFSET ?4");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, session_id);
        bindNullableText(stmt, 2, actor_id);
        _ = c.sqlite3_bind_int64(stmt, 3, @intCast(limit));
        _ = c.sqlite3_bind_int64(stmt, 4, @intCast(offset));
        var messages: std.ArrayListUnmanaged(Message) = .empty;
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            try messages.append(allocator, .{ .role = try columnText(allocator, stmt, 0), .content = try columnText(allocator, stmt, 1), .created_at_ms = c.sqlite3_column_int64(stmt, 2) });
        }
        return .{ .total = total, .messages = try messages.toOwnedSlice(allocator) };
    }

    pub fn createJob(self: *Self, allocator: std.mem.Allocator, input: JobInput) !Job {
        const id = try ids.make(allocator, "job_");
        const now = ids.nowMs();
        const stmt = try self.prepare("INSERT INTO jobs (id,job_type,status,scope,permissions_json,object_type,object_id,input_json,result_json,error_text,attempts,locked_until_ms,worker_id,created_at_ms,updated_at_ms) VALUES (?1,?2,'queued',?3,?4,?5,?6,?7,'{}',NULL,0,NULL,NULL,?8,?9)");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        bindText(stmt, 2, input.job_type);
        bindText(stmt, 3, input.scope);
        bindText(stmt, 4, input.permissions_json);
        bindText(stmt, 5, input.object_type);
        bindText(stmt, 6, input.object_id);
        bindText(stmt, 7, input.input_json);
        _ = c.sqlite3_bind_int64(stmt, 8, now);
        _ = c.sqlite3_bind_int64(stmt, 9, now);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
        try self.insertAuditActor("job.created", input.actor_id, "job", id);
        return .{
            .id = id,
            .job_type = input.job_type,
            .status = "queued",
            .scope = input.scope,
            .permissions_json = input.permissions_json,
            .object_type = input.object_type,
            .object_id = input.object_id,
            .input_json = input.input_json,
            .result_json = "{}",
            .error_text = null,
            .attempts = 0,
            .created_at_ms = now,
            .updated_at_ms = now,
        };
    }

    pub fn getJob(self: *Self, allocator: std.mem.Allocator, id: []const u8) !?Job {
        const stmt = try self.prepare("SELECT id,job_type,status,scope,permissions_json,object_type,object_id,input_json,result_json,error_text,attempts,created_at_ms,updated_at_ms,locked_until_ms,worker_id FROM jobs WHERE id = ?1 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return null;
        return try readJob(allocator, stmt);
    }

    pub fn listJobs(self: *Self, allocator: std.mem.Allocator, input: JobListInput) ![]Job {
        const visible_limit = @max(@as(usize, 1), @min(input.limit, 500));
        const include_expired_running = jobListIncludesExpiredRunning(input);
        const stmt = if (include_expired_running)
            try self.prepare("SELECT id,job_type,status,scope,permissions_json,object_type,object_id,input_json,result_json,error_text,attempts,created_at_ms,updated_at_ms,locked_until_ms,worker_id FROM jobs WHERE (status = ?1 OR (status = 'running' AND locked_until_ms IS NOT NULL AND locked_until_ms <= ?2)) ORDER BY created_at_ms DESC")
        else if (input.status) |_|
            try self.prepare("SELECT id,job_type,status,scope,permissions_json,object_type,object_id,input_json,result_json,error_text,attempts,created_at_ms,updated_at_ms,locked_until_ms,worker_id FROM jobs WHERE status = ?1 ORDER BY created_at_ms DESC")
        else
            try self.prepare("SELECT id,job_type,status,scope,permissions_json,object_type,object_id,input_json,result_json,error_text,attempts,created_at_ms,updated_at_ms,locked_until_ms,worker_id FROM jobs ORDER BY created_at_ms DESC");
        defer _ = c.sqlite3_finalize(stmt);
        if (include_expired_running) {
            bindText(stmt, 1, input.status.?);
            _ = c.sqlite3_bind_int64(stmt, 2, ids.nowMs());
        } else if (input.status) |status| bindText(stmt, 1, status);
        var out: std.ArrayListUnmanaged(Job) = .empty;
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const scope = try columnText(allocator, stmt, 3);
            const permissions = try columnText(allocator, stmt, 4);
            if (!try self.recordVisibleWithPolicy(allocator, scope, permissions, input.scopes_json)) continue;
            try out.append(allocator, try readJobWithAcl(allocator, stmt, scope, permissions));
            if (out.items.len >= visible_limit) break;
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn upsertConnectorCursor(self: *Self, allocator: std.mem.Allocator, input: ConnectorCursorInput) !ConnectorCursor {
        const now = ids.nowMs();
        const stmt = try self.prepare("INSERT INTO connector_cursors (connector,scope,cursor,config_json,permissions_json,updated_at_ms) VALUES (?1,?2,?3,?4,?5,?6) ON CONFLICT(connector, scope) DO UPDATE SET cursor=excluded.cursor, config_json=excluded.config_json, permissions_json=excluded.permissions_json, updated_at_ms=excluded.updated_at_ms");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, input.connector);
        bindText(stmt, 2, input.scope);
        bindText(stmt, 3, input.cursor);
        bindText(stmt, 4, input.config_json);
        bindText(stmt, 5, input.permissions_json);
        _ = c.sqlite3_bind_int64(stmt, 6, now);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.UpsertFailed;
        try self.insertAuditActor("connector_cursor.upserted", input.actor_id, "connector", input.connector);
        return .{
            .connector = try allocator.dupe(u8, input.connector),
            .scope = try allocator.dupe(u8, input.scope),
            .cursor = try allocator.dupe(u8, input.cursor),
            .config_json = try allocator.dupe(u8, input.config_json),
            .permissions_json = try allocator.dupe(u8, input.permissions_json),
            .updated_at_ms = now,
        };
    }

    pub fn getConnectorCursor(self: *Self, allocator: std.mem.Allocator, connector: []const u8, scope: []const u8) !?ConnectorCursor {
        const stmt = try self.prepare("SELECT connector,scope,cursor,config_json,permissions_json,updated_at_ms FROM connector_cursors WHERE connector = ?1 AND scope = ?2 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, connector);
        bindText(stmt, 2, scope);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return null;
        return try readConnectorCursor(allocator, stmt);
    }

    pub fn listConnectorCursors(self: *Self, allocator: std.mem.Allocator, input: ConnectorCursorListInput) ![]ConnectorCursor {
        const stmt = if (input.connector) |_|
            try self.prepare("SELECT connector,scope,cursor,config_json,permissions_json,updated_at_ms FROM connector_cursors WHERE connector = ?1 ORDER BY updated_at_ms DESC LIMIT ?2")
        else
            try self.prepare("SELECT connector,scope,cursor,config_json,permissions_json,updated_at_ms FROM connector_cursors ORDER BY updated_at_ms DESC LIMIT ?2");
        defer _ = c.sqlite3_finalize(stmt);
        if (input.connector) |connector| bindText(stmt, 1, connector);
        _ = c.sqlite3_bind_int64(stmt, 2, @intCast(@max(@as(usize, 1), @min(input.limit, 500))));
        var out: std.ArrayListUnmanaged(ConnectorCursor) = .empty;
        errdefer out.deinit(allocator);
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const scope = try columnText(allocator, stmt, 1);
            const permissions = try columnText(allocator, stmt, 4);
            if (!try self.recordVisibleWithPolicy(allocator, scope, permissions, input.scopes_json)) continue;
            try out.append(allocator, try readConnectorCursorWithAcl(allocator, stmt, scope, permissions));
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn claimJob(self: *Self, id: []const u8) !bool {
        return self.claimJobAs(id, default_job_worker_id);
    }

    pub fn claimJobAs(self: *Self, id: []const u8, worker_id: []const u8) !bool {
        const now = ids.nowMs();
        const claim_worker_id = effectiveWorkerId(worker_id, default_job_worker_id);
        const stmt = try self.prepare("UPDATE jobs SET status = 'running', attempts = attempts + 1, locked_until_ms = ?1, worker_id = ?2, updated_at_ms = ?3 WHERE id = ?4 AND (status = 'queued' OR (status = 'running' AND locked_until_ms IS NOT NULL AND locked_until_ms <= ?5))");
        defer _ = c.sqlite3_finalize(stmt);
        _ = c.sqlite3_bind_int64(stmt, 1, now + default_job_lease_ms);
        bindText(stmt, 2, claim_worker_id);
        _ = c.sqlite3_bind_int64(stmt, 3, now);
        bindText(stmt, 4, id);
        _ = c.sqlite3_bind_int64(stmt, 5, now);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.UpdateFailed;
        const changed = c.sqlite3_changes(self.db) > 0;
        if (changed) try self.insertAudit("job.claimed", "job", id);
        return changed;
    }

    pub fn finishJob(self: *Self, id: []const u8, status: []const u8, result_json: []const u8, error_text: ?[]const u8) !bool {
        return self.finishJobAs(id, status, result_json, error_text, null);
    }

    pub fn finishJobAs(self: *Self, id: []const u8, status: []const u8, result_json: []const u8, error_text: ?[]const u8, worker_id: ?[]const u8) !bool {
        const stmt = if (worker_id != null)
            try self.prepare("UPDATE jobs SET status = ?1, result_json = ?2, error_text = ?3, locked_until_ms = NULL, worker_id = NULL, updated_at_ms = ?4 WHERE id = ?5 AND status = 'running' AND worker_id = ?6")
        else
            try self.prepare("UPDATE jobs SET status = ?1, result_json = ?2, error_text = ?3, locked_until_ms = NULL, worker_id = NULL, updated_at_ms = ?4 WHERE id = ?5");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, status);
        bindText(stmt, 2, result_json);
        bindNullableText(stmt, 3, error_text);
        _ = c.sqlite3_bind_int64(stmt, 4, ids.nowMs());
        bindText(stmt, 5, id);
        if (worker_id) |worker| bindText(stmt, 6, worker);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.UpdateFailed;
        const changed = c.sqlite3_changes(self.db) > 0;
        if (changed) try self.insertAudit("job.finished", "job", id);
        return changed;
    }

    fn readJob(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt) !Job {
        const scope = try columnText(allocator, stmt, 3);
        const permissions = try columnText(allocator, stmt, 4);
        return readJobWithAcl(allocator, stmt, scope, permissions);
    }

    fn readJobWithAcl(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt, scope: []const u8, permissions_json: []const u8) !Job {
        return .{
            .id = try columnText(allocator, stmt, 0),
            .job_type = try columnText(allocator, stmt, 1),
            .status = try columnText(allocator, stmt, 2),
            .scope = scope,
            .permissions_json = permissions_json,
            .object_type = try columnText(allocator, stmt, 5),
            .object_id = try columnText(allocator, stmt, 6),
            .input_json = try columnText(allocator, stmt, 7),
            .result_json = try columnText(allocator, stmt, 8),
            .error_text = try columnTextNullable(allocator, stmt, 9),
            .attempts = c.sqlite3_column_int64(stmt, 10),
            .created_at_ms = c.sqlite3_column_int64(stmt, 11),
            .updated_at_ms = c.sqlite3_column_int64(stmt, 12),
            .locked_until_ms = columnIntNullable(stmt, 13),
            .worker_id = try columnTextNullable(allocator, stmt, 14),
        };
    }

    fn readConnectorCursor(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt) !ConnectorCursor {
        const scope = try columnText(allocator, stmt, 1);
        const permissions = try columnText(allocator, stmt, 4);
        return readConnectorCursorWithAcl(allocator, stmt, scope, permissions);
    }

    fn readConnectorCursorWithAcl(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt, scope: []const u8, permissions_json: []const u8) !ConnectorCursor {
        return .{
            .connector = try columnText(allocator, stmt, 0),
            .scope = scope,
            .cursor = try columnText(allocator, stmt, 2),
            .config_json = try columnText(allocator, stmt, 3),
            .permissions_json = permissions_json,
            .updated_at_ms = c.sqlite3_column_int64(stmt, 5),
        };
    }

    pub fn listConflicts(self: *Self, allocator: std.mem.Allocator, input: ConflictListInput) ![]KnowledgeConflict {
        const stmt = if (input.status) |_|
            try self.prepare("SELECT id,conflict_type,object_a_type,object_a_id,object_b_type,object_b_id,scope,permissions_json,status,summary,created_at_ms,resolved_at_ms FROM knowledge_conflicts WHERE status = ?1 ORDER BY created_at_ms DESC LIMIT ?2")
        else
            try self.prepare("SELECT id,conflict_type,object_a_type,object_a_id,object_b_type,object_b_id,scope,permissions_json,status,summary,created_at_ms,resolved_at_ms FROM knowledge_conflicts ORDER BY created_at_ms DESC LIMIT ?2");
        defer _ = c.sqlite3_finalize(stmt);
        if (input.status) |status| bindText(stmt, 1, status);
        _ = c.sqlite3_bind_int64(stmt, 2, @intCast(@max(@as(usize, 1), @min(input.limit, 500))));
        var out: std.ArrayListUnmanaged(KnowledgeConflict) = .empty;
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const scope = try columnText(allocator, stmt, 6);
            const permissions = try columnText(allocator, stmt, 7);
            const conflict = try readConflictWithAcl(allocator, stmt, scope, permissions);
            if (!try self.conflictVisible(allocator, conflict, input.scopes_json)) continue;
            try out.append(allocator, conflict);
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn scanConflicts(self: *Self, allocator: std.mem.Allocator, input: ConflictListInput) ![]KnowledgeConflict {
        const atoms = try self.visibleMemoryAtomsForConflictScan(allocator, input.scopes_json, @max(@as(usize, 50), @min(input.limit * 10, 1000)));
        for (atoms, 0..) |a, i| {
            if (!domain.isDefaultVisibleStatus(a.status)) continue;
            for (atoms[i + 1 ..]) |b| {
                if (!domain.isDefaultVisibleStatus(b.status)) continue;
                if (!sameConflictSubject(a, b)) continue;
                if (std.mem.eql(u8, a.object, b.object)) continue;
                try self.insertConflictIfMissing(allocator, a, b);
            }
        }
        return try self.listConflicts(allocator, input);
    }

    fn visibleMemoryAtomsForConflictScan(self: *Self, allocator: std.mem.Allocator, scopes_json: []const u8, limit: usize) ![]domain.MemoryAtom {
        const stmt = try self.prepare("SELECT id,subject_entity_id,predicate,object,text,scope,confidence,status,source_ids_json,evidence_ranges_json,created_by,created_at_ms,valid_from_ms,valid_until_ms,last_verified_at_ms,owner,permissions_json,tags_json FROM memory_atoms ORDER BY created_at_ms DESC LIMIT ?1");
        defer _ = c.sqlite3_finalize(stmt);
        _ = c.sqlite3_bind_int64(stmt, 1, @intCast(limit));
        var out: std.ArrayListUnmanaged(domain.MemoryAtom) = .empty;
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const atom = try readMemoryAtom(allocator, stmt);
            if (!try self.recordVisibleWithPolicy(allocator, atom.scope, atom.permissions_json, scopes_json)) continue;
            try out.append(allocator, atom);
        }
        return out.toOwnedSlice(allocator);
    }

    fn sameConflictSubject(a: domain.MemoryAtom, b: domain.MemoryAtom) bool {
        if (!std.mem.eql(u8, a.scope, b.scope)) return false;
        if (!std.mem.eql(u8, a.predicate, b.predicate)) return false;
        if (a.subject_entity_id != null and b.subject_entity_id != null) return std.mem.eql(u8, a.subject_entity_id.?, b.subject_entity_id.?);
        return true;
    }

    fn insertConflictIfMissing(self: *Self, allocator: std.mem.Allocator, a: domain.MemoryAtom, b: domain.MemoryAtom) !void {
        const a_id = if (std.mem.lessThan(u8, a.id, b.id)) a.id else b.id;
        const b_id = if (std.mem.lessThan(u8, a.id, b.id)) b.id else a.id;
        const summary = try std.fmt.allocPrint(allocator, "Potential conflicting {s}: {s} vs {s}", .{ a.predicate, a.object, b.object });
        const permissions = try combinedPermissionsJson(allocator, a.permissions_json, b.permissions_json);
        const id = try ids.make(allocator, "cnf_");
        const now = ids.nowMs();
        const stmt = try self.prepare("INSERT OR IGNORE INTO knowledge_conflicts (id,conflict_type,object_a_type,object_a_id,object_b_type,object_b_id,scope,permissions_json,status,summary,created_at_ms,resolved_at_ms) VALUES (?1,'memory_atom_conflict','memory_atom',?2,'memory_atom',?3,?4,?5,'open',?6,?7,NULL)");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        bindText(stmt, 2, a_id);
        bindText(stmt, 3, b_id);
        bindText(stmt, 4, a.scope);
        bindText(stmt, 5, permissions);
        bindText(stmt, 6, summary);
        _ = c.sqlite3_bind_int64(stmt, 7, now);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
        if (c.sqlite3_changes(self.db) > 0) try self.insertAudit("conflict.detected", "knowledge_conflict", id);
    }

    fn readConflictWithAcl(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt, scope: []const u8, permissions_json: []const u8) !KnowledgeConflict {
        return .{
            .id = try columnText(allocator, stmt, 0),
            .conflict_type = try columnText(allocator, stmt, 1),
            .object_a_type = try columnText(allocator, stmt, 2),
            .object_a_id = try columnText(allocator, stmt, 3),
            .object_b_type = try columnText(allocator, stmt, 4),
            .object_b_id = try columnText(allocator, stmt, 5),
            .scope = scope,
            .permissions_json = permissions_json,
            .status = try columnText(allocator, stmt, 8),
            .summary = try columnText(allocator, stmt, 9),
            .created_at_ms = c.sqlite3_column_int64(stmt, 10),
            .resolved_at_ms = if (c.sqlite3_column_type(stmt, 11) == c.SQLITE_NULL) null else c.sqlite3_column_int64(stmt, 11),
        };
    }

    fn conflictVisible(self: *Self, allocator: std.mem.Allocator, conflict: KnowledgeConflict, scopes_json: []const u8) !bool {
        if (std.mem.eql(u8, conflict.object_a_type, "memory_atom") and std.mem.eql(u8, conflict.object_b_type, "memory_atom")) {
            const a = (try self.getMemoryAtom(allocator, conflict.object_a_id)) orelse return false;
            const b = (try self.getMemoryAtom(allocator, conflict.object_b_id)) orelse return false;
            return (try self.recordVisibleWithPolicy(allocator, a.scope, a.permissions_json, scopes_json)) and
                (try self.recordVisibleWithPolicy(allocator, b.scope, b.permissions_json, scopes_json));
        }
        return try self.recordVisibleWithPolicy(allocator, conflict.scope, conflict.permissions_json, scopes_json);
    }

    fn countSql(self: *Self, sql: [*:0]const u8) !i64 {
        const stmt = try self.prepare(sql);
        defer _ = c.sqlite3_finalize(stmt);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return 0;
        return c.sqlite3_column_int64(stmt, 0);
    }
};

pub const PostgresStore = struct {
    allocator: std.mem.Allocator,
    transport: postgres_transport.QueryTransport,

    pub fn init(allocator: std.mem.Allocator, url: []const u8) !PostgresStore {
        const owned = try postgres_transport.withConnectTimeout(allocator, url);
        defer allocator.free(owned);
        var self = PostgresStore{ .allocator = allocator, .transport = try postgres_transport.QueryTransport.init(allocator, owned) };
        errdefer self.deinit();
        try self.prepareExistingTablesForSchema();
        try self.runSql(migrations.postgres_schema);
        try self.applySchemaMigrations();
        try self.assertSchemaCurrent();
        return self;
    }

    pub fn deinit(self: *PostgresStore) void {
        self.transport.deinit();
    }

    pub fn health(self: *PostgresStore) bool {
        self.runSql("SELECT 1;") catch return false;
        return true;
    }

    pub fn schemaVersion(self: *PostgresStore) !i64 {
        const text = try self.queryText(self.allocator, "SELECT coalesce(max(version), 0)::text FROM schema_migrations");
        defer self.allocator.free(text);
        return std.fmt.parseInt(i64, text, 10) catch 0;
    }

    fn assertSchemaCurrent(self: *PostgresStore) !void {
        var version: i64 = 1;
        while (version <= migrations.expected_schema_version) : (version += 1) {
            if (!try self.schemaMigrationPresent(version)) return error.SchemaMigrationIncomplete;
        }
        if (try self.schemaVersion() != migrations.expected_schema_version) return error.SchemaMigrationIncomplete;
    }

    fn schemaMigrationPresent(self: *PostgresStore, version: i64) !bool {
        const expected = migrations.expectedMigration(version) orelse return false;
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const version_text = try std.fmt.allocPrint(allocator, "{d}", .{version});
        const text = try self.queryParamsText(
            allocator,
            "SELECT CASE WHEN EXISTS (SELECT 1 FROM schema_migrations WHERE version = $1::bigint AND name = $2 AND checksum = $3) THEN 'true' ELSE 'false' END",
            &.{ version_text, expected.name, expected.checksum },
        );
        return std.mem.eql(u8, text, "true");
    }

    fn runSql(self: *PostgresStore, sql: []const u8) !void {
        const out = try self.queryRaw(self.allocator, sql);
        self.allocator.free(out);
    }

    fn prepareExistingTablesForSchema(self: *PostgresStore) !void {
        try self.runSql(
            \\DO $$ BEGIN
            \\  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema = 'public' AND table_name = 'session_messages')
            \\     AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'session_messages' AND column_name = 'actor_id') THEN
            \\    ALTER TABLE session_messages ADD COLUMN actor_id text;
            \\  END IF;
            \\  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema = 'public' AND table_name = 'session_usage')
            \\     AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'session_usage' AND column_name = 'actor_id') THEN
            \\    ALTER TABLE session_usage ADD COLUMN actor_id text;
            \\  END IF;
            \\END $$;
        );
    }

    fn queryRaw(self: *PostgresStore, allocator: std.mem.Allocator, sql: []const u8) ![]u8 {
        return self.transport.queryRaw(allocator, sql);
    }

    fn queryParamsRaw(self: *PostgresStore, allocator: std.mem.Allocator, sql: []const u8, params: []const ?[]const u8) ![]u8 {
        return self.transport.queryParamsRaw(allocator, sql, params);
    }

    fn queryText(self: *PostgresStore, allocator: std.mem.Allocator, sql: []const u8) ![]u8 {
        return self.queryRaw(allocator, sql);
    }

    fn queryParamsText(self: *PostgresStore, allocator: std.mem.Allocator, sql: []const u8, params: []const ?[]const u8) ![]u8 {
        return self.queryParamsRaw(allocator, sql, params);
    }

    fn runParams(self: *PostgresStore, allocator: std.mem.Allocator, sql: []const u8, params: []const ?[]const u8) !void {
        const out = try self.queryParamsRaw(allocator, sql, params);
        allocator.free(out);
    }

    fn insertAudit(self: *PostgresStore, allocator: std.mem.Allocator, event_type: []const u8, actor_id: ?[]const u8, object_type: []const u8, object_id: []const u8) !void {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const sql_allocator = allocator;
        const now_text = try std.fmt.allocPrint(arena.allocator(), "{d}", .{ids.nowMs()});
        try self.runParams(
            sql_allocator,
            "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) VALUES ($1,$2,$3,$4,'{}'::jsonb,$5::bigint)",
            &.{ event_type, actor_id, object_type, object_id, now_text },
        );
    }

    pub fn listAuditEvents(self: *PostgresStore, allocator: std.mem.Allocator, since_id: i64, limit: usize) ![]AuditEvent {
        const capped = @max(@as(usize, 1), @min(limit, 5000));
        const since_text = try std.fmt.allocPrint(allocator, "{d}", .{since_id});
        defer allocator.free(since_text);
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{capped});
        defer allocator.free(limit_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT id,event_type,actor,object_type,object_id,payload_json,created_at_ms FROM audit_events WHERE id > $1::bigint ORDER BY id LIMIT $2::bigint",
            &.{ since_text, limit_text },
        );
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(AuditEvent) = .empty;
        errdefer out.deinit(allocator);
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                const obj = item.object;
                try out.append(allocator, .{
                    .id = json.intField(obj, "id") orelse 0,
                    .event_type = try dupStringField(allocator, obj, "event_type", ""),
                    .actor = try dupNullableStringField(allocator, obj, "actor"),
                    .object_type = try dupStringField(allocator, obj, "object_type", ""),
                    .object_id = try dupStringField(allocator, obj, "object_id", ""),
                    .payload_json = try rawJsonField(allocator, obj, "payload_json", "{}"),
                    .created_at_ms = json.intField(obj, "created_at_ms") orelse 0,
                });
            }
        }
        return out.toOwnedSlice(allocator);
    }

    fn applySchemaMigrations(self: *PostgresStore) !void {
        try self.runSql(
            \\BEGIN;
            \\ALTER TABLE artifacts ADD COLUMN IF NOT EXISTS scope text NOT NULL DEFAULT 'workspace';
            \\ALTER TABLE artifacts ADD COLUMN IF NOT EXISTS fields_json jsonb NOT NULL DEFAULT '{}'::jsonb;
            \\ALTER TABLE schema_migrations ADD COLUMN IF NOT EXISTS checksum text NOT NULL DEFAULT '';
            \\ALTER TABLE entities ADD COLUMN IF NOT EXISTS scope text NOT NULL DEFAULT 'workspace';
            \\ALTER TABLE entities ADD COLUMN IF NOT EXISTS permissions_json jsonb NOT NULL DEFAULT '[]'::jsonb;
            \\ALTER TABLE relations ADD COLUMN IF NOT EXISTS scope text NOT NULL DEFAULT 'workspace';
            \\ALTER TABLE relations ADD COLUMN IF NOT EXISTS permissions_json jsonb NOT NULL DEFAULT '[]'::jsonb;
            \\ALTER TABLE context_packs ADD COLUMN IF NOT EXISTS required_scopes_json jsonb NOT NULL DEFAULT '["admin"]'::jsonb;
            \\ALTER TABLE context_packs ADD COLUMN IF NOT EXISTS actor_id text;
            \\ALTER TABLE context_packs ADD COLUMN IF NOT EXISTS actor_isolated boolean NOT NULL DEFAULT false;
            \\ALTER TABLE context_packs ADD COLUMN IF NOT EXISTS included_result_refs_json jsonb NOT NULL DEFAULT '[]'::jsonb;
            \\ALTER TABLE vector_chunks ADD COLUMN IF NOT EXISTS heading_path_json jsonb NOT NULL DEFAULT '[]'::jsonb;
            \\ALTER TABLE jobs ADD COLUMN IF NOT EXISTS permissions_json jsonb NOT NULL DEFAULT '[]'::jsonb;
