    pub fn createMemoryAtom(self: *PostgresStore, allocator: std.mem.Allocator, input: MemoryAtomInput) !domain.MemoryAtom {
        const id = try idOrMake(allocator, input.id, "mem_");
        const now = ids.nowMs();
        const status = input.status orelse domain.defaultMemoryStatus(input.created_by, input.scope);
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        const confidence_text = try std.fmt.allocPrint(allocator, "{d}", .{input.confidence});
        defer allocator.free(confidence_text);
        const valid_from_text: ?[]const u8 = if (input.valid_from_ms) |valid_from| try std.fmt.allocPrint(allocator, "{d}", .{valid_from}) else null;
        defer if (valid_from_text) |value| allocator.free(value);
        const valid_until_text: ?[]const u8 = if (input.valid_until_ms) |valid_until| try std.fmt.allocPrint(allocator, "{d}", .{valid_until}) else null;
        defer if (valid_until_text) |value| allocator.free(value);
        try self.runParams(
            allocator,
            "WITH inserted AS (" ++
                "INSERT INTO memory_atoms (id,subject_entity_id,predicate,object,text,scope,confidence,status,source_ids_json,evidence_ranges_json,created_by,created_at_ms,valid_from_ms,valid_until_ms,last_verified_at_ms,owner,permissions_json,tags_json) VALUES ($1,$2,$3,$4,$5,$6,$7::double precision,$8,$9::jsonb,$10::jsonb,$11,$12::bigint,$13::bigint,$14::bigint,NULL,$15,$16::jsonb,$17::jsonb) RETURNING id" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'memory_atom.created',$18,'memory_atom',id,'{}'::jsonb,$19::bigint FROM inserted RETURNING 1" ++
                ") SELECT count(*)::text FROM inserted",
            &.{ id, input.subject_entity_id, input.predicate, input.object, input.text, input.scope, confidence_text, status, input.source_ids_json, input.evidence_ranges_json, input.created_by, now_text, valid_from_text, valid_until_text, input.owner, input.permissions_json, input.tags_json, input.actor_id, now_text },
        );
        return .{ .id = id, .subject_entity_id = input.subject_entity_id, .predicate = input.predicate, .object = input.object, .text = input.text, .scope = input.scope, .confidence = input.confidence, .status = status, .source_ids_json = input.source_ids_json, .evidence_ranges_json = input.evidence_ranges_json, .created_by = input.created_by, .created_at_ms = now, .valid_from_ms = input.valid_from_ms, .valid_until_ms = input.valid_until_ms, .last_verified_at_ms = null, .owner = input.owner, .permissions_json = input.permissions_json, .tags_json = input.tags_json };
    }

    pub fn importMemoryAtomsAtomic(self: *PostgresStore, allocator: std.mem.Allocator, inputs: []const PreparedMemoryImport) ![]domain.MemoryAtom {
        try self.runSql("BEGIN");
        errdefer self.runSql("ROLLBACK") catch {};

        var out: std.ArrayListUnmanaged(domain.MemoryAtom) = .empty;
        errdefer out.deinit(allocator);

        for (inputs) |prepared| {
            var atom_input = prepared.atom;
            if (prepared.generated_source) |source_input| {
                const source = try self.createSource(allocator, source_input);
                atom_input.source_ids_json = try singleJsonString(allocator, source.id);
                atom_input.evidence_ranges_json = try evidenceRangeJson(allocator, source.id, atom_input.text.len, "snapshot_import");
            }

            const atom = try self.createMemoryAtom(allocator, atom_input);
            try out.append(allocator, atom);
        }

        try self.runSql("COMMIT");
        return out.toOwnedSlice(allocator);
    }

    pub fn applyFeedMemoryAtomAtomic(self: *PostgresStore, allocator: std.mem.Allocator, input: FeedMemoryApplyInput) !FeedMemoryApplyResult {
        try self.runSql("BEGIN");
        errdefer self.runSql("ROLLBACK") catch {};

        var atom_input = input.prepared.atom;
        if (input.prepared.generated_source) |source_input| {
            const source = try self.createSource(allocator, source_input);
            atom_input.source_ids_json = try singleJsonString(allocator, source.id);
            atom_input.evidence_ranges_json = try evidenceRangeJson(allocator, source.id, atom_input.text.len, "generated_source");
        }

        const atom = try self.createMemoryAtom(allocator, atom_input);
        const event_id = if (input.reserved_event_id) |reserved| blk: {
            if (!try self.markFeedEventApplied(reserved, input.event.object_type, atom.id, input.event.payload_json)) return error.FeedReservationConsumed;
            break :blk reserved;
        } else try self.appendFeedEvent(.{
            .event_type = input.event.event_type,
            .operation = input.event.operation,
            .object_type = input.event.object_type,
            .object_id = atom.id,
            .scope = input.event.scope,
            .permissions_json = input.event.permissions_json,
            .actor_id = input.event.actor_id,
            .dedupe_key = input.event.dedupe_key,
            .causality_json = input.event.causality_json,
            .payload_json = input.event.payload_json,
            .status = "applied",
        });

        try self.runSql("COMMIT");
        return .{ .event_id = event_id, .atom = atom };
    }

    pub fn applyFeedAgentMemoryAtomic(self: *PostgresStore, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput) !FeedAgentMemoryApplyResult {
        try self.runSql("BEGIN");
        errdefer self.runSql("ROLLBACK") catch {};

        var object_id: []const u8 = input.delete_key orelse "agent_memory";
        var entry: ?domain.AgentMemory = null;
        var deleted = false;
        if (input.input) |memory_input| {
            var auditable = memory_input;
            if (auditable.writer_actor_id == null) auditable.writer_actor_id = input.writer_actor_id orelse input.event.actor_id;
            const saved = try self.agentMemoryStore(allocator, auditable);
            object_id = saved.id;
            entry = saved;
        } else if (input.delete_key) |key| {
            deleted = if (input.delete_all)
                try self.agentMemoryDeleteAll(key, input.delete_owner_actor_id, input.writer_actor_id orelse input.event.actor_id)
            else
                try self.agentMemoryDelete(key, input.delete_session_id, input.delete_owner_actor_id, input.writer_actor_id orelse input.event.actor_id);
            object_id = key;
        }

        const event_id = if (input.reserved_event_id) |reserved| blk: {
            if (!try self.markFeedEventApplied(reserved, input.event.object_type, object_id, input.event.payload_json)) return error.FeedReservationConsumed;
            break :blk reserved;
        } else try self.appendFeedEvent(.{
            .event_type = input.event.event_type,
            .operation = input.event.operation,
            .object_type = input.event.object_type,
            .object_id = object_id,
            .scope = input.event.scope,
            .permissions_json = input.event.permissions_json,
            .actor_id = input.event.actor_id,
            .dedupe_key = input.event.dedupe_key,
            .causality_json = input.event.causality_json,
            .payload_json = input.event.payload_json,
            .status = "applied",
        });

        try self.runSql("COMMIT");
        return .{ .event_id = event_id, .object_id = object_id, .entry = entry, .deleted = deleted };
    }

    pub fn applyExtractedKnowledge(self: *PostgresStore, allocator: std.mem.Allocator, input: ExtractedKnowledgeInput) !ExtractedKnowledgeResult {
        const ResolvedRelation = struct {
            input: ExtractedRelationInput,
            from_entity: domain.Entity,
            to_entity: domain.Entity,
        };

        try self.runSql("BEGIN");
        errdefer self.runSql("ROLLBACK") catch {};

        var entity_list: std.ArrayListUnmanaged(domain.Entity) = .empty;
        errdefer entity_list.deinit(allocator);
        const base_entities = try self.resolveExtractedEntitiesPg(allocator, input.entity_names_json, input.source.scope, input.source.permissions_json, input.actor_id);
        for (base_entities) |entity| try appendUniqueEntity(allocator, &entity_list, entity);

        var resolved_relations: std.ArrayListUnmanaged(ResolvedRelation) = .empty;
        errdefer resolved_relations.deinit(allocator);
        for (input.relations) |relation_input| {
            const from_entity = try self.resolveEntity(allocator, .{
                .entity_type = "project",
                .name = relation_input.from_entity_name,
                .scope = input.source.scope,
                .permissions_json = input.source.permissions_json,
                .actor_id = input.actor_id,
            });
            const to_entity = try self.resolveEntity(allocator, .{
                .entity_type = "project",
                .name = relation_input.to_entity_name,
                .scope = input.source.scope,
                .permissions_json = input.source.permissions_json,
                .actor_id = input.actor_id,
            });
            try appendUniqueEntity(allocator, &entity_list, from_entity);
            try appendUniqueEntity(allocator, &entity_list, to_entity);
            try resolved_relations.append(allocator, .{ .input = relation_input, .from_entity = from_entity, .to_entity = to_entity });
        }

        const entities = try entity_list.toOwnedSlice(allocator);
        const related_entity_ids_json = try entityIdsJson(allocator, entities);

        try self.runParams(
            allocator,
            "UPDATE sources SET related_entities_json = $1::jsonb WHERE id = $2",
            &.{ related_entity_ids_json, input.source.id },
        );

        var artifact: ?domain.Artifact = null;
        if (input.artifact) |base_artifact_input| {
            var artifact_input = base_artifact_input;
            artifact_input.related_entities_json = related_entity_ids_json;
            artifact = try self.createArtifact(allocator, artifact_input);
        }

        var atoms: std.ArrayListUnmanaged(domain.MemoryAtom) = .empty;
        errdefer atoms.deinit(allocator);
        const subject_entity_id = if (entities.len > 0) entities[0].id else null;
        for (input.atoms) |base_atom_input| {
            var atom_input = base_atom_input;
            if (atom_input.subject_entity_id == null) atom_input.subject_entity_id = subject_entity_id;
            try atoms.append(allocator, try self.createMemoryAtom(allocator, atom_input));
        }

        var relations: std.ArrayListUnmanaged(domain.Relation) = .empty;
        errdefer relations.deinit(allocator);
        for (resolved_relations.items) |resolved| {
            try relations.append(allocator, try self.createRelation(allocator, .{
                .from_entity_id = resolved.from_entity.id,
                .relation_type = resolved.input.relation_type,
                .to_entity_id = resolved.to_entity.id,
                .source_ids_json = resolved.input.source_ids_json,
                .scope = resolved.input.scope,
                .permissions_json = resolved.input.permissions_json,
                .confidence = resolved.input.confidence,
                .status = resolved.input.status,
                .actor_id = resolved.input.actor_id,
            }));
        }

        try self.runSql("COMMIT");
        return .{ .artifact = artifact, .entities = entities, .relations = try relations.toOwnedSlice(allocator), .atoms = try atoms.toOwnedSlice(allocator) };
    }

    fn resolveExtractedEntitiesPg(self: *PostgresStore, allocator: std.mem.Allocator, names_json: []const u8, scope: []const u8, permissions_json: []const u8, actor_id: ?[]const u8) ![]domain.Entity {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, names_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return allocator.alloc(domain.Entity, 0);
        var out: std.ArrayListUnmanaged(domain.Entity) = .empty;
        errdefer out.deinit(allocator);
        for (parsed.value.array.items) |item| {
            if (item != .string) continue;
            const owned_name = try allocator.dupe(u8, item.string);
            try out.append(allocator, try self.resolveEntity(allocator, .{
                .entity_type = "project",
                .name = owned_name,
                .scope = scope,
                .permissions_json = permissions_json,
                .actor_id = actor_id,
            }));
        }
        return out.toOwnedSlice(allocator);
    }

