    pub fn contextPackLifecycleTarget(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !?PrimitiveLifecycleTarget {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT id,included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated FROM context_packs WHERE id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        const obj = parsed.value.object;
        const sources = try rawJsonField(allocator, obj, "included_sources_json", "[]");
        const artifacts = try rawJsonField(allocator, obj, "included_artifacts_json", "[]");
        const atoms = try rawJsonField(allocator, obj, "included_memory_atoms_json", "[]");
        const refs = try rawJsonField(allocator, obj, "included_result_refs_json", "[]");
        const required_scopes = try rawJsonField(allocator, obj, "required_scopes_json", "[\"admin\"]");
        const row_actor_id = try dupNullableStringField(allocator, obj, "actor_id");
        const actor_isolated = json.boolField(obj, "actor_isolated") orelse false;
        if (!try self.contextPackVisible(allocator, sources, artifacts, atoms, refs, required_scopes, row_actor_id, actor_isolated, scopes_json, actor_id, true)) return null;
        return .{
            .object_id = try allocator.dupe(u8, id),
            .scope = try lifecycleScopeFromRequiredScopesJson(allocator, required_scopes),
            .permissions_json = required_scopes,
        };
    }

    pub fn search(self: *PostgresStore, allocator: std.mem.Allocator, input: SearchInput) ![]domain.SearchResult {
        const limit = @max(@as(usize, 1), @min(input.limit, 100));
        var plan = try retrieval_mod.buildPlanWithAdaptive(allocator, input.query, input.use_vector, input.allow_reranker, .{ .enabled = input.adaptive_retrieval });
        defer plan.deinit(allocator);
        var semantic_input = input;
        semantic_input.query = plan.websearch_query;
        var graph_input = semantic_input;
        var exact_graph_query: ?[]u8 = null;
        if (retrieval_mod.queryHasEntityHint(input.query)) {
            exact_graph_query = try retrieval_mod.buildExactWebsearchQuery(allocator, input.query);
            graph_input.query = exact_graph_query.?;
        }
        defer if (exact_graph_query) |query| allocator.free(query);
        var keyword_results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        errdefer keyword_results.deinit(allocator);

        if (plan.use_keyword) try self.searchPgKeywordCandidates(allocator, semantic_input, graph_input, &keyword_results);
        pgSortSearchResults(keyword_results.items);

        var vector_results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        errdefer vector_results.deinit(allocator);
        if (plan.use_vector and input.query.len > 0) {
            try self.searchPgVectorCandidates(allocator, input, plan.expanded_query, &vector_results);
        }
        if (plan.use_graph or keyword_results.items.len > 0) {
            try self.expandPgGraphCandidates(allocator, input, &keyword_results);
        }

        return try self.fusePgSearchResults(allocator, input, keyword_results.items, vector_results.items, limit);
    }

    fn searchPgKeywordCandidates(self: *PostgresStore, allocator: std.mem.Allocator, input: SearchInput, graph_input: SearchInput, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        try self.searchPgMemoryAtoms(allocator, input, results);
        try self.searchPgSpaces(allocator, input, results);
        try self.searchPgPolicyScopes(allocator, input, results);
        try self.searchPgSources(allocator, input, results);
        try self.searchPgArtifacts(allocator, input, results);
        try self.searchPgEntities(allocator, graph_input, results);
        try self.searchPgRelations(allocator, graph_input, results);
        try self.searchPgContextPacks(allocator, input, results);
        try self.searchPgFeedEvents(allocator, input, results);
        try self.searchPgAgentMemories(allocator, input, results);
        if (input.include_sessions) try self.searchPgSessions(allocator, input, results);
    }

    fn fusePgSearchResults(self: *PostgresStore, allocator: std.mem.Allocator, input: SearchInput, keyword_results: []const domain.SearchResult, vector_results: []const domain.SearchResult, limit: usize) ![]domain.SearchResult {
        _ = self;
        if (vector_results.len == 0) {
            return finalizeSearchResults(allocator, input, keyword_results, limit);
        }
        const keyword_ranked = try allocator.alloc(retrieval_mod.RankedItem, keyword_results.len);
        defer allocator.free(keyword_ranked);
        for (keyword_results, 0..) |result, i| {
            keyword_ranked[i] = .{ .id = result.id, .score = result.score, .created_at_ms = result.created_at_ms, .confidence = result.confidence };
        }
        const vector_ranked = try allocator.alloc(retrieval_mod.RankedItem, vector_results.len);
        defer allocator.free(vector_ranked);
        for (vector_results, 0..) |result, i| {
            vector_ranked[i] = .{ .id = result.id, .score = result.score, .created_at_ms = result.created_at_ms, .confidence = result.confidence };
        }
        const lists = [_][]const retrieval_mod.RankedItem{ keyword_ranked, vector_ranked };
        const fused = try retrieval_mod.reciprocalRankFusion(allocator, &lists, 60, @max(limit * 4, @as(usize, 20)));
        defer allocator.free(fused);
        var out: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        for (fused) |ranked| {
            const keyword_result = findSearchResultByIdGlobal(keyword_results, ranked.id);
            const vector_result = findSearchResultByIdGlobal(vector_results, ranked.id);
            if (chooseFusedSearchResult(keyword_result, vector_result)) |result| {
                var copy = result;
                copy.score += ranked.score;
                try out.append(allocator, copy);
            }
        }
        return finalizeSearchResults(allocator, input, out.items, limit);
    }

    fn recordVisibleWithPolicy(self: *PostgresStore, allocator: std.mem.Allocator, scope: []const u8, permissions_json: []const u8, scopes_json: []const u8) !bool {
        if (!domain.recordVisible(scope, permissions_json, scopes_json)) return false;
        const policy = try self.getPolicyScope(allocator, scope);
        if (policy) |p| return domain.recordVisible(p.scope, p.permissions_json, scopes_json);
        return true;
    }

    fn recordVisibleWithPolicyForActor(self: *PostgresStore, allocator: std.mem.Allocator, scope: []const u8, permissions_json: []const u8, scopes_json: []const u8, actor_id: ?[]const u8) !bool {
        if (try self.recordVisibleWithPolicy(allocator, scope, permissions_json, scopes_json)) return true;
        const actor = actor_id orelse return false;
        if (!permissionsVisibleForActor(allocator, permissions_json, scopes_json, actor)) return false;
        if (!domain.scopeVisible(scope, scopes_json) and !domain.isActorOwnedAgentMemoryScope(scope, actor)) return false;
        const policy = try self.getPolicyScope(allocator, scope);
        if (policy) |p| return domain.recordVisible(p.scope, p.permissions_json, scopes_json);
        return true;
    }

    fn agentMemoryResultVisible(self: *PostgresStore, allocator: std.mem.Allocator, owner_actor_id: []const u8, scope: []const u8, permissions: []const u8, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) !bool {
        return access.agentMemoryVisible(allocator, .{
            .owner_actor_id = owner_actor_id,
            .scope = scope,
            .permissions_json = permissions,
            .session_id = session_id,
            .request_actor_id = actor_id,
            .request_scopes_json = scopes_json,
            .record_visible = try self.recordVisibleWithPolicy(allocator, scope, permissions, scopes_json),
            .session_visible = if (session_id) |sid| sessionVisibleForScopes(allocator, sid, scopes_json) else true,
        });
    }

    pub fn upsertVectorChunk(self: *PostgresStore, allocator: std.mem.Allocator, input: VectorChunkInput) !VectorChunk {
        const parsed_embedding = try vector_mod.embeddingFromJson(allocator, input.embedding_json);
        defer allocator.free(parsed_embedding);
        if (!try self.vectorBackingObjectExists(allocator, input.object_type, input.object_id)) return error.InvalidVectorTarget;
        const id = try std.fmt.allocPrint(allocator, "vec_{s}_{d}", .{ input.object_id, input.chunk_ordinal });
        const now = ids.nowMs();
        const chunk_ordinal = try std.fmt.allocPrint(allocator, "{d}", .{input.chunk_ordinal});
        defer allocator.free(chunk_ordinal);
        const dimensions = try std.fmt.allocPrint(allocator, "{d}", .{input.dimensions});
        defer allocator.free(dimensions);
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        try self.runParams(
            allocator,
            "INSERT INTO vector_chunks (id,object_type,object_id,chunk_ordinal,text,scope,permissions_json,heading_path_json,embedding_json,embedding,model,dimensions,created_at_ms,updated_at_ms) " ++
                "VALUES ($1,$2,$3,$4::bigint,$5,$6,$7::jsonb,$8::jsonb,$9::jsonb,$10::vector,$11,$12::bigint,$13::bigint,$14::bigint) " ++
                "ON CONFLICT(id) DO UPDATE SET text=excluded.text, scope=excluded.scope, permissions_json=excluded.permissions_json, heading_path_json=excluded.heading_path_json, embedding_json=excluded.embedding_json, embedding=excluded.embedding, model=excluded.model, dimensions=excluded.dimensions, updated_at_ms=excluded.updated_at_ms",
            &.{ id, input.object_type, input.object_id, chunk_ordinal, input.text, input.scope, input.permissions_json, input.heading_path_json, input.embedding_json, input.embedding_json, input.model, dimensions, now_text, now_text },
        );
        const outbox_payload = try vectorUpsertPayloadJson(allocator, id);
        defer allocator.free(outbox_payload);
        _ = try self.enqueueVectorOutbox(.{ .action = "upsert", .object_type = input.object_type, .object_id = input.object_id, .payload_json = outbox_payload });
        try self.insertAudit(allocator, "vector_chunk.upserted", input.actor_id, "vector_chunk", id);
        return .{ .id = id, .object_type = input.object_type, .object_id = input.object_id, .chunk_ordinal = input.chunk_ordinal, .text = input.text, .scope = input.scope, .permissions_json = input.permissions_json, .heading_path_json = input.heading_path_json, .embedding_json = input.embedding_json, .model = input.model, .dimensions = input.dimensions, .created_at_ms = now, .updated_at_ms = now };
    }

    pub fn getVectorChunk(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !?VectorChunk {
        const parsed = try self.queryArrayParamsJson(allocator, "SELECT id,object_type,object_id,chunk_ordinal,text,scope,permissions_json,heading_path_json,embedding_json,model,dimensions,created_at_ms,updated_at_ms FROM vector_chunks WHERE id = $1 LIMIT 1", &.{id});
        defer parsed.deinit();
        if (parsed.value != .array or parsed.value.array.items.len == 0) return null;
        const item = parsed.value.array.items[0];
        if (item != .object) return null;
        return try readPgVectorChunk(allocator, item.object);
    }

    pub fn listVectorChunks(self: *PostgresStore, allocator: std.mem.Allocator, limit: usize, offset: usize) ![]VectorChunk {
        const capped = @max(@as(usize, 1), @min(limit, 10000));
        const inner = try std.fmt.allocPrint(allocator, "SELECT id,object_type,object_id,chunk_ordinal,text,scope,permissions_json,heading_path_json,embedding_json,model,dimensions,created_at_ms,updated_at_ms FROM vector_chunks ORDER BY updated_at_ms DESC, id LIMIT {d} OFFSET {d}", .{ capped, offset });
        defer allocator.free(inner);
        const parsed = try self.queryArrayParamsJson(allocator, inner, &.{});
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(VectorChunk) = .empty;
        errdefer out.deinit(allocator);
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                try out.append(allocator, try readPgVectorChunk(allocator, item.object));
            }
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn deleteVectorChunk(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, actor_id: ?[]const u8) !bool {
        var chunk = (try self.getVectorChunk(allocator, id)) orelse return false;
        defer deinitVectorChunk(allocator, &chunk);
        const text = try self.queryParamsText(allocator, "WITH deleted AS (DELETE FROM vector_chunks WHERE id = $1 RETURNING 1) SELECT count(*)::text FROM deleted", &.{id});
        defer allocator.free(text);
        const changed = (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
        if (!changed) return false;
        const outbox_payload = try vectorUpsertPayloadJson(allocator, id);
        defer allocator.free(outbox_payload);
        _ = try self.enqueueVectorOutbox(.{
            .action = "delete",
            .object_type = chunk.object_type,
            .object_id = chunk.object_id,
            .payload_json = outbox_payload,
        });
        try self.insertAudit(allocator, "vector_chunk.deleted", actor_id, "vector_chunk", id);
        return true;
    }

    fn deleteVectorChunksForObject(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, actor_id: ?[]const u8) !usize {
        const parsed = try self.queryArrayParamsJson(allocator, "SELECT id FROM vector_chunks WHERE object_type = $1 AND object_id = $2 ORDER BY id", &.{ object_type, object_id });
        defer parsed.deinit();
        var ids_to_delete: std.ArrayListUnmanaged([]const u8) = .empty;
        defer {
            for (ids_to_delete.items) |chunk_id| allocator.free(chunk_id);
            ids_to_delete.deinit(allocator);
        }
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                try ids_to_delete.append(allocator, try dupStringField(allocator, item.object, "id", ""));
            }
        }
        var deleted: usize = 0;
        for (ids_to_delete.items) |chunk_id| {
            if (try self.deleteVectorChunk(allocator, chunk_id, actor_id)) deleted += 1;
        }
        return deleted;
    }

    pub fn vectorSearch(self: *PostgresStore, allocator: std.mem.Allocator, input: VectorSearchInput) ![]vector_mod.VectorMatch {
        const query = try vector_mod.embeddingFromJson(allocator, input.embedding_json);
        defer allocator.free(query);
        if (query.len == 0) return allocator.alloc(vector_mod.VectorMatch, 0);
        {
            const candidate_limit = pgSearchCandidateLimit(input.limit, 20, 5000);
            const dimensions_text = try std.fmt.allocPrint(allocator, "{d}", .{query.len});
            defer allocator.free(dimensions_text);
            const candidate_limit_text = try std.fmt.allocPrint(allocator, "{d}", .{candidate_limit});
            defer allocator.free(candidate_limit_text);
            const ma_visible = try pgRecordVisibleSql(allocator, "ma.scope", "ma.permissions_json", input.scopes_json, input.actor_id);
            const source_visible = try pgRecordVisibleSql(allocator, "src.scope", "src.permissions_json", input.scopes_json, input.actor_id);
            const artifact_visible = try pgRecordVisibleSql(allocator, "art.scope", "art.permissions_json", input.scopes_json, input.actor_id);
            const entity_visible = try pgRecordVisibleSql(allocator, "ent.scope", "ent.permissions_json", input.scopes_json, input.actor_id);
            const relation_visible = try pgRecordVisibleSql(allocator, "rel.scope", "rel.permissions_json", input.scopes_json, input.actor_id);
            const relation_from_visible = try pgRecordVisibleSql(allocator, "rel_from.scope", "rel_from.permissions_json", input.scopes_json, input.actor_id);
            const relation_to_visible = try pgRecordVisibleSql(allocator, "rel_to.scope", "rel_to.permissions_json", input.scopes_json, input.actor_id);
            const agent_memory_visible = try pgRecordVisibleSql(allocator, "ami.scope", "ami.permissions_json", input.scopes_json, input.actor_id);
            const agent_memory_prefilter = try std.fmt.allocPrint(allocator, "(({s}) OR ($2::text IS NOT NULL AND ami.actor_id = $2))", .{agent_memory_visible});
            const space_visible = try pgRecordVisibleSql(allocator, "sp.scope", "sp.permissions_json", input.scopes_json, input.actor_id);
            const policy_visible = try pgRecordVisibleSql(allocator, "ps.scope", "ps.permissions_json", input.scopes_json, input.actor_id);
            const context_actor_filter = "(cp.actor_isolated = false OR ($2::text IS NOT NULL AND cp.actor_id = $2))";
            const ma_status_filter = if (input.include_deprecated) "" else " AND ma.status NOT IN ('rejected','deprecated','superseded')";
            const artifact_status_filter = if (input.include_deprecated) "" else " AND art.status NOT IN ('rejected','deprecated','superseded')";
            const relation_status_filter = if (input.include_deprecated) "" else " AND rel.status NOT IN ('rejected','deprecated','superseded')";
            const agent_status_filter = if (input.include_deprecated) "" else " AND agma.status NOT IN ('rejected','deprecated','superseded')";
            const inner = try std.fmt.allocPrint(
                allocator,
                "SELECT vc.id,vc.object_id,vc.object_type,vc.text,vc.scope,vc.permissions_json,vc.heading_path_json,vc.embedding_json,(1 - (vc.embedding <=> $1::vector)) AS score " ++
                    "FROM vector_chunks vc " ++
                    "LEFT JOIN memory_atoms ma ON vc.object_type = 'memory_atom' AND ma.id = vc.object_id " ++
                    "LEFT JOIN sources src ON vc.object_type = 'source' AND src.id = vc.object_id " ++
                    "LEFT JOIN artifacts art ON vc.object_type = 'artifact' AND art.id = vc.object_id " ++
                    "LEFT JOIN entities ent ON vc.object_type = 'entity' AND ent.id = vc.object_id " ++
                    "LEFT JOIN relations rel ON vc.object_type = 'relation' AND rel.id = vc.object_id " ++
                    "LEFT JOIN entities rel_from ON rel_from.id = rel.from_entity_id " ++
                    "LEFT JOIN entities rel_to ON rel_to.id = rel.to_entity_id " ++
                    "LEFT JOIN context_packs cp ON vc.object_type = 'context_pack' AND cp.id = vc.object_id " ++
                    "LEFT JOIN agent_memory_items ami ON vc.object_type = 'agent_memory' AND ami.id = vc.object_id " ++
                    "LEFT JOIN memory_atoms agma ON agma.id = ami.memory_atom_id " ++
                    "LEFT JOIN spaces sp ON vc.object_type = 'space' AND sp.id = vc.object_id " ++
                    "LEFT JOIN policy_scopes ps ON vc.object_type = 'policy_scope' AND ps.scope = vc.object_id " ++
                    "WHERE vc.embedding IS NOT NULL AND vc.dimensions = $3::bigint AND ((" ++
                    "vc.object_type = 'memory_atom' AND ma.id IS NOT NULL{s} AND ({s})) OR (" ++
                    "vc.object_type = 'source' AND src.id IS NOT NULL AND ({s})) OR (" ++
                    "vc.object_type = 'artifact' AND art.id IS NOT NULL{s} AND ({s})) OR (" ++
                    "vc.object_type = 'entity' AND ent.id IS NOT NULL AND ({s})) OR (" ++
                    "vc.object_type = 'relation' AND rel.id IS NOT NULL{s} AND ({s}) AND rel_from.id IS NOT NULL AND ({s}) AND rel_to.id IS NOT NULL AND ({s})) OR (" ++
                    "vc.object_type = 'context_pack' AND cp.id IS NOT NULL AND {s}) OR (" ++
                    "vc.object_type = 'agent_memory' AND ami.id IS NOT NULL AND agma.id IS NOT NULL{s} AND ({s})) OR (" ++
                    "vc.object_type = 'space' AND sp.id IS NOT NULL AND ({s})) OR (" ++
                    "vc.object_type = 'policy_scope' AND ps.scope IS NOT NULL AND ({s}))) " ++
                    "ORDER BY vc.embedding <=> $1::vector LIMIT $4::bigint",
                .{
                    ma_status_filter,
                    ma_visible,
                    source_visible,
                    artifact_status_filter,
                    artifact_visible,
                    entity_visible,
                    relation_status_filter,
                    relation_visible,
                    relation_from_visible,
                    relation_to_visible,
                    context_actor_filter,
                    agent_status_filter,
                    agent_memory_prefilter,
                    space_visible,
                    policy_visible,
                },
            );
            const parsed = try self.queryArrayParamsJson(allocator, inner, &.{ input.embedding_json, input.actor_id, dimensions_text, candidate_limit_text });
            defer parsed.deinit();
            var out: std.ArrayListUnmanaged(vector_mod.VectorMatch) = .empty;
            errdefer {
                vector_mod.deinitMatches(allocator, out.items);
                out.deinit(allocator);
            }
            if (parsed.value == .array) {
                for (parsed.value.array.items) |item| {
                    if (item != .object) continue;
                    const obj = item.object;
                    const scope = try dupStringField(allocator, obj, "scope", "");
                    const permissions = try rawJsonField(allocator, obj, "permissions_json", "[]");
                    defer allocator.free(permissions);
                    const object_id = try dupStringField(allocator, obj, "object_id", "");
                    const object_type = try dupStringField(allocator, obj, "object_type", "");
                    if (!try self.vectorChunkObjectVisible(allocator, object_type, object_id, scope, permissions, input.scopes_json, input.actor_id, input.include_deprecated)) {
                        allocator.free(scope);
                        allocator.free(object_id);
                        allocator.free(object_type);
                        continue;
                    }
                    try out.append(allocator, .{
                        .id = try dupStringField(allocator, obj, "id", ""),
                        .object_id = object_id,
                        .object_type = object_type,
                        .text = try dupStringField(allocator, obj, "text", ""),
                        .scope = scope,
                        .heading_path_json = try rawJsonField(allocator, obj, "heading_path_json", "[]"),
                        .score = @floatCast(json.floatField(obj, "score") orelse 0),
                    });
                    if (out.items.len >= @max(@as(usize, 1), @min(input.limit, 100))) break;
                }
            }
            return out.toOwnedSlice(allocator);
        }
    }

    pub fn vectorSearchCandidates(self: *PostgresStore, allocator: std.mem.Allocator, input: VectorSearchInput, candidates: []const vector_runtime.Candidate) ![]vector_mod.VectorMatch {
        var out: std.ArrayListUnmanaged(vector_mod.VectorMatch) = .empty;
        errdefer {
            vector_mod.deinitMatches(allocator, out.items);
            out.deinit(allocator);
        }
        const capped = @max(@as(usize, 1), @min(input.limit, 100));
        for (candidates) |candidate| {
            var chunk = (try self.getVectorChunk(allocator, candidate.vector_id)) orelse continue;
            defer deinitVectorChunk(allocator, &chunk);
            if (!try self.vectorChunkObjectVisible(allocator, chunk.object_type, chunk.object_id, chunk.scope, chunk.permissions_json, input.scopes_json, input.actor_id, input.include_deprecated)) continue;
            try out.append(allocator, try vectorMatchFromChunk(allocator, chunk, candidate.score));
            if (out.items.len >= capped) break;
        }
        return out.toOwnedSlice(allocator);
    }

    fn vectorChunkObjectVisible(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, chunk_scope: []const u8, chunk_permissions: []const u8, scopes_json: []const u8, actor_id: ?[]const u8, include_deprecated: bool) !bool {
        _ = chunk_scope;
        _ = chunk_permissions;
        if (std.mem.eql(u8, object_type, "memory_atom")) {
            var atom = (try self.getMemoryAtom(allocator, object_id)) orelse return false;
            defer deinitMemoryAtom(allocator, &atom);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(atom.status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, atom.scope, atom.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "source")) {
            const source = (try self.getSource(allocator, object_id)) orelse return false;
            const status = try self.primitiveLifecycleStatus(allocator, "source", source.id);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, source.scope, source.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "artifact")) {
            const artifact = (try self.getArtifact(allocator, object_id)) orelse return false;
            if (!include_deprecated and !domain.isDefaultVisibleStatus(artifact.status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, artifact.scope, artifact.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "entity")) {
            const entity = (try self.getEntity(allocator, object_id)) orelse return false;
            const status = try self.primitiveLifecycleStatus(allocator, "entity", entity.id);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, entity.scope, entity.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "relation")) {
            return try self.vectorRelationVisible(allocator, object_id, scopes_json, actor_id, include_deprecated);
        }
        if (std.mem.eql(u8, object_type, "context_pack")) {
            return try self.vectorContextPackVisible(allocator, object_id, scopes_json, actor_id, include_deprecated);
        }
        if (std.mem.eql(u8, object_type, "agent_memory")) {
            const entry = (try self.agentMemoryById(allocator, object_id)) orelse return false;
            return try self.agentMemoryResultVisible(allocator, entry.actor_id, entry.scope, entry.permissions_json, entry.session_id, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "space")) {
            const space = (try self.getSpace(allocator, object_id)) orelse return false;
            const status = try self.primitiveLifecycleStatus(allocator, "space", space.id);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, space.scope, space.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "policy_scope")) {
            const policy = (try self.getPolicyScope(allocator, object_id)) orelse return false;
            const status = try self.primitiveLifecycleStatus(allocator, "policy_scope", policy.scope);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, policy.scope, policy.permissions_json, scopes_json, actor_id);
        }
        return false;
    }

    fn vectorBackingObjectExists(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8) !bool {
        if (std.mem.eql(u8, object_type, "memory_atom")) return (try self.getMemoryAtom(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "source")) return (try self.getSource(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "artifact")) return (try self.getArtifact(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "entity")) return (try self.getEntity(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "relation")) return (try self.getRelation(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "context_pack")) return try self.contextPackExists(allocator, object_id);
        if (std.mem.eql(u8, object_type, "agent_memory")) return (try self.agentMemoryById(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "space")) return (try self.getSpace(allocator, object_id)) != null;
        if (std.mem.eql(u8, object_type, "policy_scope")) return (try self.getPolicyScope(allocator, object_id)) != null;
        return false;
    }

    pub fn vectorObjectAcl(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, actor_id: ?[]const u8) !?VectorObjectAcl {
        if (std.mem.eql(u8, object_type, "memory_atom")) {
            const atom = (try self.getMemoryAtom(allocator, object_id)) orelse return null;
            return .{ .scope = atom.scope, .permissions_json = atom.permissions_json };
        }
        if (std.mem.eql(u8, object_type, "source")) {
            const source = (try self.getSource(allocator, object_id)) orelse return null;
            return .{ .scope = source.scope, .permissions_json = source.permissions_json };
        }
        if (std.mem.eql(u8, object_type, "artifact")) {
            const artifact = (try self.getArtifact(allocator, object_id)) orelse return null;
            return .{ .scope = artifact.scope, .permissions_json = artifact.permissions_json };
        }
        if (std.mem.eql(u8, object_type, "entity")) {
            const entity = (try self.getEntity(allocator, object_id)) orelse return null;
            return .{ .scope = entity.scope, .permissions_json = entity.permissions_json };
        }
        if (std.mem.eql(u8, object_type, "relation")) {
            const relation = (try self.getRelation(allocator, object_id)) orelse return null;
            return .{ .scope = relation.scope, .permissions_json = relation.permissions_json };
        }
        if (std.mem.eql(u8, object_type, "context_pack")) {
            return try self.vectorContextPackAcl(allocator, object_id, actor_id);
        }
        if (std.mem.eql(u8, object_type, "agent_memory")) {
            const entry = (try self.agentMemoryById(allocator, object_id)) orelse return null;
            return .{ .scope = entry.scope, .permissions_json = entry.permissions_json };
        }
        if (std.mem.eql(u8, object_type, "space")) {
            const space = (try self.getSpace(allocator, object_id)) orelse return null;
            return .{ .scope = space.scope, .permissions_json = space.permissions_json };
        }
        if (std.mem.eql(u8, object_type, "policy_scope")) {
            const policy = (try self.getPolicyScope(allocator, object_id)) orelse return null;
            return .{ .scope = policy.scope, .permissions_json = policy.permissions_json };
        }
        return null;
    }

    fn vectorRelationVisible(self: *PostgresStore, allocator: std.mem.Allocator, relation_id: []const u8, scopes_json: []const u8, actor_id: ?[]const u8, include_deprecated: bool) !bool {
        const relation = (try self.getRelation(allocator, relation_id)) orelse return false;
        if (!include_deprecated and !domain.isDefaultVisibleStatus(relation.status)) return false;
        if (!try self.recordVisibleWithPolicyForActor(allocator, relation.scope, relation.permissions_json, scopes_json, actor_id)) return false;
        const from_entity = (try self.getEntity(allocator, relation.from_entity_id)) orelse return false;
        if (!try self.recordVisibleWithPolicyForActor(allocator, from_entity.scope, from_entity.permissions_json, scopes_json, actor_id)) return false;
        const to_entity = (try self.getEntity(allocator, relation.to_entity_id)) orelse return false;
        if (!try self.recordVisibleWithPolicyForActor(allocator, to_entity.scope, to_entity.permissions_json, scopes_json, actor_id)) return false;
        return true;
    }

    fn vectorContextPackAcl(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, actor_id: ?[]const u8) !?VectorObjectAcl {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT required_scopes_json,actor_id,actor_isolated FROM context_packs WHERE id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        const obj = parsed.value.object;
        const required_scopes = try rawJsonField(allocator, obj, "required_scopes_json", "[]");
        const row_actor = try dupNullableStringField(allocator, obj, "actor_id");
        const actor_isolated = json.boolField(obj, "actor_isolated") orelse false;
        if (actor_isolated) {
            const actor = actor_id orelse return null;
            if (!actorMatches(actor_id, row_actor)) return null;
            return .{ .scope = try domain.defaultAgentMemoryScope(allocator, actor), .permissions_json = try domain.actorGrantJson(allocator, actor) };
        }
        return .{
            .scope = try firstScopeOrDefault(allocator, required_scopes, "public"),
            .permissions_json = required_scopes,
        };
    }

    fn vectorContextPackVisible(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, scopes_json: []const u8, actor_id: ?[]const u8, include_deprecated: bool) !bool {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated FROM context_packs WHERE id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return false;
        const obj = parsed.value.object;
        const source_ids = try rawJsonField(allocator, obj, "included_sources_json", "[]");
        const artifact_ids = try rawJsonField(allocator, obj, "included_artifacts_json", "[]");
        const atom_ids = try rawJsonField(allocator, obj, "included_memory_atoms_json", "[]");
        const result_refs = try rawJsonField(allocator, obj, "included_result_refs_json", "[]");
        const required_scopes = try rawJsonField(allocator, obj, "required_scopes_json", "[]");
        const row_actor = try dupNullableStringField(allocator, obj, "actor_id");
        const actor_isolated = json.boolField(obj, "actor_isolated") orelse false;
        if (!try self.contextPackVisible(allocator, source_ids, artifact_ids, atom_ids, result_refs, required_scopes, row_actor, actor_isolated, scopes_json, actor_id, include_deprecated)) return false;
        const status = try self.primitiveLifecycleStatus(allocator, "context_pack", id);
        if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
        return true;
    }

    fn agentMemoryById(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !?domain.AgentMemory {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT ami.id,ami.key,ma.text AS content,ami.category,ami.timestamp_ms,ami.session_id,ami.actor_id,ami.writer_actor_id,ami.scope,ami.permissions_json,ma.confidence AS score " ++
                "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id WHERE ami.id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        return try readPgAgentMemory(allocator, parsed.value.object);
    }

    pub fn enqueueVectorOutbox(self: *PostgresStore, input: VectorOutboxInput) !i64 {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const text = try self.queryParamsText(
            allocator,
            "INSERT INTO vector_outbox (action,object_type,object_id,status,attempts,payload_json,created_at_ms,updated_at_ms) VALUES ($1,$2,$3,$4,0,$5::jsonb,$6::bigint,$7::bigint) RETURNING id::text",
            &.{ input.action, input.object_type, input.object_id, input.status, input.payload_json, now_text, now_text },
        );
        const id = std.fmt.parseInt(i64, text, 10) catch 0;
        if (id > 0) try self.insertAudit(self.allocator, "vector_outbox.enqueued", null, "vector_outbox", input.object_id);
        return id;
    }

    pub fn listVectorOutbox(self: *PostgresStore, allocator: std.mem.Allocator, input: VectorOutboxListInput) ![]VectorOutboxEntry {
        try self.reclaimExpiredVectorOutbox(allocator);
        const capped = @max(@as(usize, 1), @min(input.limit, 1000));
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{capped});
        defer allocator.free(limit_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT id,action,object_type,object_id,status,attempts,payload_json,created_at_ms,updated_at_ms,locked_until_ms,worker_id FROM vector_outbox " ++
                "WHERE ($1::text IS NULL OR action = $1) AND ($2::text IS NULL OR status = $2) ORDER BY id LIMIT $3::bigint",
            &.{ input.action, input.status, limit_text },
        );
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(VectorOutboxEntry) = .empty;
        errdefer out.deinit(allocator);
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                try out.append(allocator, try readPgVectorOutboxEntry(allocator, item.object));
            }
        }
        return out.toOwnedSlice(allocator);
    }

    fn reclaimExpiredVectorOutbox(self: *PostgresStore, allocator: std.mem.Allocator) !void {
        const now = ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        try self.runParams(
            allocator,
            "UPDATE vector_outbox SET status = 'pending', locked_until_ms = NULL, worker_id = NULL, updated_at_ms = $1::bigint WHERE status = 'running' AND locked_until_ms IS NOT NULL AND locked_until_ms <= $2::bigint",
            &.{ now_text, now_text },
        );
    }

    pub fn claimVectorOutbox(self: *PostgresStore, id: i64) !bool {
        return self.claimVectorOutboxAs(id, default_vector_outbox_worker_id);
    }

    pub fn claimVectorOutboxAs(self: *PostgresStore, id: i64, worker_id: []const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = ids.nowMs();
        const locked_until = try std.fmt.allocPrint(allocator, "{d}", .{now + default_vector_outbox_lease_ms});
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const id_text = try std.fmt.allocPrint(allocator, "{d}", .{id});
        const claim_worker_id = effectiveWorkerId(worker_id, default_vector_outbox_worker_id);
        const text = try self.queryParamsText(
            allocator,
            "WITH updated AS (UPDATE vector_outbox SET status = 'running', attempts = attempts + 1, locked_until_ms = $1::bigint, worker_id = $2, updated_at_ms = $3::bigint WHERE id = $4::bigint AND (status = 'pending' OR (status = 'running' AND locked_until_ms IS NOT NULL AND locked_until_ms <= $5::bigint)) RETURNING 1) SELECT count(*)::text FROM updated",
            &.{ locked_until, claim_worker_id, now_text, id_text, now_text },
        );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
    }

    pub fn finishVectorOutbox(self: *PostgresStore, id: i64, status: []const u8) !bool {
        return self.finishVectorOutboxAs(id, status, null);
    }

    pub fn finishVectorOutboxAs(self: *PostgresStore, id: i64, status: []const u8, worker_id: ?[]const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{ids.nowMs()});
        const id_text = try std.fmt.allocPrint(allocator, "{d}", .{id});
        const text = if (worker_id) |worker|
            try self.queryParamsText(
                allocator,
                "WITH updated AS (UPDATE vector_outbox SET status = $1, locked_until_ms = NULL, worker_id = NULL, updated_at_ms = $2::bigint WHERE id = $3::bigint AND status = 'running' AND worker_id = $4 RETURNING 1) SELECT count(*)::text FROM updated",
                &.{ status, now_text, id_text, worker },
            )
        else
            try self.queryParamsText(
                allocator,
                "WITH updated AS (UPDATE vector_outbox SET status = $1, locked_until_ms = NULL, worker_id = NULL, updated_at_ms = $2::bigint WHERE id = $3::bigint RETURNING 1) SELECT count(*)::text FROM updated",
                &.{ status, now_text, id_text },
            );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
    }

