    }

    pub fn listFeedEvents(self: *PostgresStore, allocator: std.mem.Allocator, input: FeedListInput) ![]FeedEvent {
        const floor = try self.feedCursorFloor(allocator);
        if (!input.ignore_cursor_floor and input.since_id < floor) return error.CursorExpired;
        const visible_limit = @max(@as(usize, 1), @min(input.limit, 500));
        const since_text = try std.fmt.allocPrint(allocator, "{d}", .{input.since_id});
        defer allocator.free(since_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT id,event_type,operation,object_type,object_id,scope,permissions_json,actor_id,dedupe_key,causality_json,payload_json,status,created_at_ms,applied_at_ms,compacted_at_ms FROM memory_feed_events WHERE id > $1::bigint ORDER BY id ASC",
            &.{since_text},
        );
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(FeedEvent) = .empty;
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const event = try readPgFeedEvent(allocator, item.object);
            if (!try self.recordVisibleWithPolicyForActor(allocator, event.scope, event.permissions_json, input.scopes_json, input.actor_id)) continue;
            try out.append(allocator, event);
            if (out.items.len >= visible_limit) break;
        };
        return out.toOwnedSlice(allocator);
    }

    pub fn getFeedEventByDedupeKey(self: *PostgresStore, allocator: std.mem.Allocator, dedupe_key: []const u8) !?FeedEvent {
        const parsed = try self.queryRowParamsJson(allocator, "SELECT id,event_type,operation,object_type,object_id,scope,permissions_json,actor_id,dedupe_key,causality_json,payload_json,status,created_at_ms,applied_at_ms,compacted_at_ms FROM memory_feed_events WHERE dedupe_key = $1 LIMIT 1", &.{dedupe_key});
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        return try readPgFeedEvent(allocator, parsed.value.object);
    }

    fn feedCursorFloor(self: *PostgresStore, allocator: std.mem.Allocator) !i64 {
        const text = try self.queryText(allocator, "SELECT coalesce((SELECT cursor_floor FROM memory_feed_state WHERE id = 1), 0)::text");
        defer allocator.free(text);
        return std.fmt.parseInt(i64, text, 10) catch 0;
    }

    pub fn feedProjectionCursorFloor(self: *PostgresStore, allocator: std.mem.Allocator, name: []const u8) !i64 {
        const text = try self.queryParamsText(allocator, "SELECT coalesce((SELECT cursor_floor FROM memory_feed_cursors WHERE name = $1 LIMIT 1), 0)::text", &.{name});
        defer allocator.free(text);
        return std.fmt.parseInt(i64, text, 10) catch 0;
    }

    pub fn feedStatus(self: *PostgresStore, allocator: std.mem.Allocator, input: FeedStatusInput) !FeedStatus {
        const floor = try self.feedCursorFloor(allocator);
        const max_text = try self.queryText(allocator, "SELECT coalesce(max(id), 0)::text FROM memory_feed_events");
        defer allocator.free(max_text);
        const max_id = std.fmt.parseInt(i64, max_text, 10) catch 0;
        const floor_text = try std.fmt.allocPrint(allocator, "{d}", .{floor});
        defer allocator.free(floor_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT scope,permissions_json,status FROM memory_feed_events WHERE id > $1::bigint",
            &.{floor_text},
        );
        defer parsed.deinit();
        var visible: usize = 0;
        var pending: usize = 0;
        var applying: usize = 0;
        var applied_count: usize = 0;
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const scope = json.stringField(item.object, "scope") orelse "workspace";
            const permissions = try rawJsonField(allocator, item.object, "permissions_json", "[]");
            if (!try self.recordVisibleWithPolicyForActor(allocator, scope, permissions, input.scopes_json, input.actor_id)) continue;
            const status = json.stringField(item.object, "status") orelse "";
            visible += 1;
            if (std.mem.eql(u8, status, "pending")) pending += 1 else if (std.mem.eql(u8, status, "applying")) applying += 1 else if (std.mem.eql(u8, status, "applied")) applied_count += 1;
        };
        return .{ .cursor_floor = floor, .max_event_id = max_id, .visible_events = visible, .pending_events = pending, .applying_events = applying, .applied_events = applied_count };
    }

    pub fn compactFeed(self: *PostgresStore, before_id: i64, actor_id: ?[]const u8) !FeedCompactResult {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const max_text = try self.queryText(allocator, "SELECT coalesce(max(id), 0)::text FROM memory_feed_events");
        const max_id = std.fmt.parseInt(i64, max_text, 10) catch 0;
        const floor = @max(@as(i64, 0), @min(before_id, max_id));
        const now = ids.nowMs();
        const floor_text = try std.fmt.allocPrint(allocator, "{d}", .{floor});
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const compacted_text = try self.queryParamsText(allocator, "SELECT count(*)::text FROM memory_feed_events WHERE id <= $1::bigint AND compacted_at_ms IS NULL", &.{floor_text});
        const compacted = std.fmt.parseInt(usize, compacted_text, 10) catch 0;
        const payload = try std.fmt.allocPrint(allocator, "{{\"compacted_events\":{d}}}", .{compacted});
        _ = try self.queryParamsText(
            allocator,
            "WITH updated_events AS (" ++
                "UPDATE memory_feed_events SET compacted_at_ms = $1::bigint WHERE id <= $2::bigint AND compacted_at_ms IS NULL RETURNING id" ++
                "), updated_state AS (" ++
                "UPDATE memory_feed_state SET cursor_floor = greatest(cursor_floor, $2::bigint), updated_at_ms = $1::bigint WHERE id = 1 RETURNING cursor_floor" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) VALUES ('memory_feed.compacted',$3,'memory_feed','cursor_floor',$4::jsonb,$1::bigint) RETURNING 1" ++
                ") SELECT coalesce((SELECT cursor_floor::text FROM updated_state), '0')",
            &.{ now_text, floor_text, actor_id, payload },
        );
        return .{ .cursor_floor = try self.feedCursorFloor(allocator), .max_event_id = max_id, .compacted_events = compacted };
    }

    pub fn compactFeedProjection(self: *PostgresStore, name: []const u8, object_type: []const u8, before_id: i64, actor_id: ?[]const u8) !FeedCompactResult {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const max_text = try self.queryText(allocator, "SELECT coalesce(max(id), 0)::text FROM memory_feed_events");
        const max_id = std.fmt.parseInt(i64, max_text, 10) catch 0;
        const old_floor = try self.feedProjectionCursorFloor(allocator, name);
        const floor = @max(@as(i64, 0), @min(before_id, max_id));
        const old_floor_text = try std.fmt.allocPrint(allocator, "{d}", .{old_floor});
        const floor_text = try std.fmt.allocPrint(allocator, "{d}", .{floor});
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{ids.nowMs()});
        const compacted_text = try self.queryParamsText(
            allocator,
            "SELECT count(*)::text FROM memory_feed_events WHERE id > $1::bigint AND id <= $2::bigint AND object_type = $3",
            &.{ old_floor_text, floor_text, object_type },
        );
        const compacted = std.fmt.parseInt(usize, compacted_text, 10) catch 0;
        var payload_buf: std.ArrayListUnmanaged(u8) = .empty;
        try payload_buf.appendSlice(allocator, "{\"projection\":");
        try json.appendString(&payload_buf, allocator, name);
        try payload_buf.print(allocator, ",\"compacted_events\":{d}}}", .{compacted});
        const payload = try payload_buf.toOwnedSlice(allocator);
        _ = try self.queryParamsText(
            allocator,
            "WITH updated_state AS (" ++
                "INSERT INTO memory_feed_cursors (name,cursor_floor,updated_at_ms) VALUES ($1,$2::bigint,$3::bigint) " ++
                "ON CONFLICT(name) DO UPDATE SET cursor_floor = greatest(memory_feed_cursors.cursor_floor, excluded.cursor_floor), updated_at_ms = excluded.updated_at_ms RETURNING cursor_floor" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) VALUES ('memory_feed_projection.compacted',$4,'memory_feed_projection',$1,$5::jsonb,$3::bigint) RETURNING 1" ++
                ") SELECT coalesce((SELECT cursor_floor::text FROM updated_state), '0')",
            &.{ name, floor_text, now_text, actor_id, payload },
        );
        return .{ .cursor_floor = try self.feedProjectionCursorFloor(allocator, name), .max_event_id = max_id, .compacted_events = compacted };
    }

