            "ORDER BY CASE WHEN ami.actor_id = $4 THEN 0 WHEN ami.actor_id LIKE 'shared:%' THEN 1 ELSE 2 END, ami.timestamp_ms DESC";
        const parsed = if (limit) |max_rows| blk: {
