test "sqlite primitive creates fail closed when audit is unavailable" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const relation_from = try store.resolveEntity(alloc, .{ .entity_type = "service", .name = "Audited A", .scope = "public" });
    const relation_to = try store.resolveEntity(alloc, .{ .entity_type = "service", .name = "Audited B", .scope = "public" });
    try testingSqliteExec(&store, "DROP TABLE audit_events");

    try std.testing.expectError(error.SqlPrepareFailed, store.resolveEntity(alloc, .{
        .entity_type = "service",
        .name = "Unaudited Entity",
        .scope = "public",
    }));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM entities WHERE name = 'Unaudited Entity'"));

    try std.testing.expectError(error.SqlPrepareFailed, store.createRelation(alloc, .{
        .from_entity_id = relation_from.id,
        .relation_type = "depends_on",
        .to_entity_id = relation_to.id,
        .scope = "public",
    }));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM relations"));

    try std.testing.expectError(error.SqlPrepareFailed, store.createSource(alloc, .{
        .title = "Unaudited source",
        .content = "must not persist without audit",
        .scope = "public",
    }));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM sources"));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM sources_fts"));

    try std.testing.expectError(error.SqlPrepareFailed, store.createArtifact(alloc, .{
        .title = "Unaudited artifact",
        .body = "must not persist without audit",
        .scope = "public",
    }));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM artifacts"));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM artifacts_fts"));

    try std.testing.expectError(error.SqlPrepareFailed, store.createMemoryAtom(alloc, .{
        .text = "Unaudited atom",
        .scope = "public",
        .created_by = "human",
    }));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM memory_atoms"));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM memory_atoms_fts"));
}

test "sqlite storage contract covers primitives lifecycle and audit events" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const source = try store.createSource(alloc, .{
        .source_type = "transcript",
        .title = "Planning transcript",
        .content = "Release checklist discussion",
        .scope = "project:nullpantry",
        .permissions_json = "[\"project:nullpantry\"]",
    });
    const loaded_source = (try store.getSource(alloc, source.id)).?;
    try std.testing.expectEqualStrings(source.id, loaded_source.id);
    try std.testing.expectEqualStrings("transcript", loaded_source.source_type);

    const artifact = try store.createArtifact(alloc, .{
        .artifact_type = "decision",
        .title = "Use Memory Atoms",
        .body = "Decision: keep memory atom as core primitive.",
        .status = "accepted",
        .source_ids_json = "[\"src_test\"]",
        .permissions_json = "[\"project:nullpantry\"]",
    });
    const loaded_artifact = (try store.getArtifact(alloc, artifact.id)).?;
    try std.testing.expectEqualStrings("accepted", loaded_artifact.status);

    const from = try store.resolveEntity(alloc, .{ .entity_type = "project", .name = "NullPantry" });
    const to = try store.resolveEntity(alloc, .{ .entity_type = "service", .name = "NullClaw" });
    const relation = try store.createRelation(alloc, .{
        .from_entity_id = from.id,
        .relation_type = "serves_context_to",
        .to_entity_id = to.id,
        .confidence = 0.91,
    });
    try std.testing.expectEqualStrings(from.id, relation.from_entity_id);
    try std.testing.expectEqualStrings(to.id, relation.to_entity_id);

    const atom = try store.createMemoryAtom(alloc, .{
        .text = "Release runbook is owned by NullPantry.",
        .scope = "project:nullpantry",
        .created_by = "human",
        .source_ids_json = "[\"src_test\"]",
        .permissions_json = "[\"project:nullpantry\"]",
    });
    try std.testing.expectEqualStrings("verified", atom.status);
    try std.testing.expect(try store.patchMemoryAtomStatus(atom.id, "stale", false));
    const stale = (try store.getMemoryAtom(alloc, atom.id)).?;
    try std.testing.expectEqualStrings("stale", stale.status);
    try std.testing.expect(try store.patchMemoryAtomStatus(atom.id, "verified", true));
    const verified = (try store.getMemoryAtom(alloc, atom.id)).?;
    try std.testing.expect(verified.last_verified_at_ms != null);

    try std.testing.expect((try testingSqliteCount(&store, "SELECT COUNT(*) FROM audit_events")) >= 7);
    const audit_events = try store.listAuditEvents(alloc, 0, 100);
    try std.testing.expect(audit_events.len >= 7);
    var migration_count_query_buf: [128]u8 = undefined;
    const migration_count_query = try std.fmt.bufPrintZ(&migration_count_query_buf, "SELECT COUNT(*) FROM schema_migrations WHERE version BETWEEN 1 AND {d}", .{migrations.expected_schema_version});
    try std.testing.expect((try testingSqliteCount(&store, migration_count_query.ptr)) == migrations.expected_schema_version);
    try std.testing.expect((try testingSqliteCount(&store, "SELECT COUNT(*) FROM schema_migrations WHERE checksum <> ''")) == migrations.expected_schema_version);
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM sqlite_master WHERE type = 'table' AND name = 'compat_memories'"));
}

test "sqlite schema migration removes obsolete compatibility and actorless session data" {
    var tmp = std.testing.tmpDir(.{});
    defer tmp.cleanup();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    const db_path = try std.fs.path.joinZ(alloc, &.{ ".zig-cache", "tmp", tmp.sub_path[0..], "legacy.db" });

    var db: ?*c.sqlite3 = null;
    const flags = c.SQLITE_OPEN_READWRITE | c.SQLITE_OPEN_CREATE | c.SQLITE_OPEN_FULLMUTEX;
    if (c.sqlite3_open_v2(db_path.ptr, &db, flags, null) != c.SQLITE_OK) return error.OpenDatabaseFailed;
    try testingRawSqliteExec(db.?,
        \\CREATE TABLE schema_migrations (version INTEGER PRIMARY KEY, name TEXT NOT NULL, applied_at_ms INTEGER NOT NULL);
        \\INSERT INTO schema_migrations (version, name, applied_at_ms) VALUES (1, 'core_primitives', 1);
        \\CREATE TABLE vector_chunks (
        \\  id TEXT PRIMARY KEY,
        \\  object_type TEXT NOT NULL,
        \\  object_id TEXT NOT NULL,
        \\  chunk_ordinal INTEGER NOT NULL DEFAULT 0,
        \\  text TEXT NOT NULL DEFAULT '',
        \\  scope TEXT NOT NULL DEFAULT 'workspace',
        \\  permissions_json TEXT NOT NULL DEFAULT '[]',
        \\  embedding_json TEXT NOT NULL,
        \\  model TEXT,
        \\  dimensions INTEGER NOT NULL,
        \\  created_at_ms INTEGER NOT NULL,
        \\  updated_at_ms INTEGER NOT NULL
        \\);
        \\INSERT INTO vector_chunks (id,object_type,object_id,chunk_ordinal,text,scope,permissions_json,embedding_json,model,dimensions,created_at_ms,updated_at_ms)
        \\VALUES ('vec_raw_0','raw','raw_1',0,'orphan vector text','public','[]','[1,0]',NULL,2,1,1);
        \\INSERT INTO vector_chunks (id,object_type,object_id,chunk_ordinal,text,scope,permissions_json,embedding_json,model,dimensions,created_at_ms,updated_at_ms)
        \\VALUES ('vec_mem_missing_0','memory_atom','mem_missing',0,'missing memory vector','public','[]','[1,0]',NULL,2,1,1);
        \\CREATE TABLE compat_memories (
        \\  key TEXT NOT NULL,
        \\  session_id TEXT,
        \\  memory_atom_id TEXT NOT NULL,
        \\  category TEXT NOT NULL DEFAULT 'core',
        \\  timestamp_ms INTEGER NOT NULL
        \\);
        \\INSERT INTO compat_memories (key, session_id, memory_atom_id, category, timestamp_ms)
        \\VALUES ('legacy.key', NULL, 'mem_legacy', 'core', 1);
        \\CREATE TABLE session_messages (
        \\  id INTEGER PRIMARY KEY AUTOINCREMENT,
        \\  session_id TEXT NOT NULL,
        \\  role TEXT NOT NULL,
        \\  content TEXT NOT NULL,
        \\  created_at_ms INTEGER NOT NULL
        \\);
        \\INSERT INTO session_messages (session_id, role, content, created_at_ms)
        \\VALUES ('legacy-session', 'user', 'legacy message', 1);
        \\CREATE TABLE session_usage (
        \\  session_id TEXT PRIMARY KEY,
        \\  total_tokens INTEGER NOT NULL,
        \\  updated_at_ms INTEGER NOT NULL
        \\);
        \\INSERT INTO session_usage (session_id, total_tokens, updated_at_ms)
        \\VALUES ('legacy-session', 10, 1);
    );
    _ = c.sqlite3_close(db.?);

    var store = try Store.initSQLite(std.testing.allocator, db_path);
    defer store.deinit();
    try std.testing.expectEqual(@as(i64, migrations.expected_schema_version), try testingSqliteCount(&store, "SELECT COUNT(*) FROM schema_migrations WHERE checksum <> ''"));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM vector_chunks WHERE object_type = 'raw' OR object_id = 'mem_missing'"));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM sqlite_master WHERE type = 'table' AND name = 'compat_memories'"));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM session_messages"));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM session_usage"));
}

