    const sibling = try store.resolveEntity(alloc, .{ .id = "ent_graph_exact_suffix", .entity_type = "service", .name = "Other Graph Node", .scope = "public" });
    const sibling_entities = try std.fmt.allocPrint(alloc, "[\"{s}\"]", .{sibling.id});

