test "sqlite applies extracted knowledge as one storage operation" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const source = try store.createSource(alloc, .{
        .source_type = "transcript",
        .title = "Extraction meeting",
        .content = "Decision: NullPantry prepares trusted context\nRisk: stale memory can mislead agents",
        .scope = "project:nullpantry",
        .permissions_json = "[\"team:platform\"]",
        .actor_id = "agent:ingest",
    });
    const source_ids = try singleJsonString(alloc, source.id);
    const applied = try store.applyExtractedKnowledge(alloc, .{
        .source = source,
        .source_ids_json = source_ids,
        .entity_names_json = "[\"NullPantry\"]",
        .artifact = .{
            .artifact_type = "meeting_note",
            .title = "meeting_note: Extraction meeting",
            .body = source.content,
            .status = "verified",
            .scope = source.scope,
            .source_ids_json = source_ids,
            .related_entities_json = "[\"NullPantry\"]",
            .permissions_json = source.permissions_json,
            .actor_id = "agent:ingest",
        },
        .atoms = &.{
            .{
                .predicate = "decision",
                .object = "NullPantry prepares trusted context",
                .text = "Decision: NullPantry prepares trusted context",
                .scope = source.scope,
                .confidence = 0.86,
                .source_ids_json = source_ids,
                .created_by = "agent",
                .permissions_json = source.permissions_json,
                .actor_id = "agent:ingest",
            },
            .{
                .predicate = "risk",
                .object = "stale memory can mislead agents",
                .text = "Risk: stale memory can mislead agents",
                .scope = source.scope,
                .confidence = 0.72,
                .source_ids_json = source_ids,
                .created_by = "agent",
                .permissions_json = source.permissions_json,
                .actor_id = "agent:ingest",
            },
        },
        .relations = &.{
            .{
                .from_entity_name = "NullPantry",
                .relation_type = "depends_on",
                .to_entity_name = "NullClaw",
                .source_ids_json = source_ids,
                .scope = source.scope,
                .permissions_json = source.permissions_json,
                .confidence = 0.78,
                .status = "proposed",
                .actor_id = "agent:ingest",
            },
        },
        .actor_id = "agent:ingest",
    });

    try std.testing.expectEqual(@as(usize, 2), applied.entities.len);
    try std.testing.expect(applied.artifact != null);
    try std.testing.expectEqual(@as(usize, 2), applied.atoms.len);
    try std.testing.expectEqual(@as(usize, 1), applied.relations.len);
    try std.testing.expectEqualStrings("depends_on", applied.relations[0].relation_type);
    try std.testing.expect(applied.atoms[0].subject_entity_id != null);
    try std.testing.expectEqualStrings(applied.entities[0].id, applied.atoms[0].subject_entity_id.?);
    const loaded_source = (try store.getSource(alloc, source.id)).?;
    const loaded_artifact = (try store.getArtifact(alloc, applied.artifact.?.id)).?;
    try std.testing.expect(std.mem.startsWith(u8, applied.entities[0].id, "ent_"));
    try std.testing.expect(std.mem.indexOf(u8, loaded_source.related_entities_json, applied.entities[0].id) != null);
    try std.testing.expect(std.mem.indexOf(u8, loaded_artifact.related_entities_json, applied.entities[0].id) != null);

    const visible = try store.search(alloc, .{
        .query = "trusted context",
        .scopes_json = "[\"project:nullpantry\",\"team:platform\"]",
        .limit = 20,
        .use_vector = false,
    });
    var saw_atom = false;
    var saw_artifact = false;
    for (visible) |result| {
        if (std.mem.eql(u8, result.result_type, "memory_atom")) saw_atom = true;
        if (std.mem.eql(u8, result.result_type, "artifact")) saw_artifact = true;
    }
    try std.testing.expect(saw_atom);
    try std.testing.expect(saw_artifact);

    const by_entity = try store.search(alloc, .{
        .query = "NullPantry",
        .scopes_json = "[\"project:nullpantry\",\"team:platform\"]",
        .limit = 20,
        .use_vector = false,
    });
    var saw_entity = false;
    var saw_entity_source = false;
    var saw_entity_artifact = false;
    for (by_entity) |result| {
        if (std.mem.eql(u8, result.id, applied.entities[0].id)) saw_entity = true;
        if (std.mem.eql(u8, result.id, source.id) and std.mem.eql(u8, result.result_type, "source")) saw_entity_source = true;
        if (std.mem.eql(u8, result.id, applied.artifact.?.id) and std.mem.eql(u8, result.result_type, "artifact")) saw_entity_artifact = true;
    }
    try std.testing.expect(saw_entity);
    try std.testing.expect(saw_entity_source);
    try std.testing.expect(saw_entity_artifact);

    const relation_results = try store.search(alloc, .{
        .query = "depends_on",
        .scopes_json = "[\"project:nullpantry\",\"team:platform\"]",
        .limit = 20,
        .use_vector = false,
    });
    var saw_relation = false;
    for (relation_results) |result| {
        if (std.mem.eql(u8, result.result_type, "relation")) saw_relation = true;
    }
    try std.testing.expect(saw_relation);
}

